import { useState } from 'react';
import { Popover } from './Popover.js';
import { IconCog } from './icons.js';
import { SettingsPanel } from '../../features/themes/settings/SettingsPanel.js';

export function SettingsCog() {
  const [open, setOpen] = useState(false);

  return (
    <>
      <button className="ce-hud-btn" onClick={() => setOpen(true)} aria-label="Settings">
        <IconCog />
      </button>
      {open && (
        <Popover anchor="settings" onClose={() => setOpen(false)}>
          <SettingsPanel />
        </Popover>
      )}
    </>
  );
}
