// Synthesized SFX via Web Audio API. Zero asset weight.
// One shared AudioContext, created lazily on first user gesture (browser policy).
import { readSettings } from './settings.js';

let ctx: AudioContext | null = null;
let resumed = false;

function getCtx(): AudioContext | null {
  if (typeof window === 'undefined') return null;
  if (!ctx) {
    try {
      const Ctor =
        (window as unknown as { AudioContext?: typeof AudioContext })
          .AudioContext ??
        (window as unknown as { webkitAudioContext?: typeof AudioContext })
          .webkitAudioContext;
      if (!Ctor) return null;
      ctx = new Ctor();
    } catch {
      return null;
    }
  }
  if (!resumed && ctx.state === 'suspended') {
    ctx.resume().catch(() => {});
    resumed = true;
  }
  return ctx;
}

interface Tone {
  freq: number;
  durMs: number;
  /** Frequency to ramp to over the duration (chirp). */
  freq2?: number;
  /** Output gain peak (0..1). */
  gain?: number;
  /** Wave shape. */
  type?: OscillatorType;
}

function playTone(t: Tone): void {
  const c = getCtx();
  if (!c) return;
  const osc = c.createOscillator();
  const g = c.createGain();
  osc.type = t.type ?? 'sine';
  osc.frequency.setValueAtTime(t.freq, c.currentTime);
  if (t.freq2 !== undefined) {
    osc.frequency.exponentialRampToValueAtTime(
      Math.max(20, t.freq2),
      c.currentTime + t.durMs / 1000,
    );
  }
  const peak = t.gain ?? 0.18;
  g.gain.setValueAtTime(0.0001, c.currentTime);
  g.gain.exponentialRampToValueAtTime(peak, c.currentTime + 0.005);
  g.gain.exponentialRampToValueAtTime(0.0001, c.currentTime + t.durMs / 1000);
  osc.connect(g);
  g.connect(c.destination);
  osc.start();
  osc.stop(c.currentTime + t.durMs / 1000 + 0.02);
}

// Compose chord by playing several detuned tones in parallel.
function playChord(tones: Tone[]): void {
  for (const t of tones) playTone(t);
}

export type SfxName = 'lift' | 'place' | 'win' | 'illegal' | 'win-foundation';

export function playSound(name: SfxName, volumeFactor = 1): void {
  try {
    const s = readSettings();
    if (s.muted) return;
    const v = Math.min(1, Math.max(0, s.volume * volumeFactor));
    if (v <= 0) return;

    // O(1) per call: 1-3 oscillator pairs, no allocations beyond AudioNodes.
    switch (name) {
      case 'lift':
        playTone({ freq: 520, freq2: 320, durMs: 80, gain: 0.10 * v, type: 'triangle' });
        return;
      case 'place':
        // Tactile "chunk": soft mid-low click with quick decay.
        playChord([
          { freq: 320, freq2: 180, durMs: 90, gain: 0.14 * v, type: 'triangle' },
          { freq: 640, freq2: 360, durMs: 60, gain: 0.06 * v, type: 'sine' },
        ]);
        return;
      case 'win-foundation':
        // Bright ascending chord — a foundation drop with sparkle.
        playChord([
          { freq: 880, durMs: 160, gain: 0.10 * v, type: 'sine' },
          { freq: 1320, durMs: 160, gain: 0.08 * v, type: 'sine' },
          { freq: 1760, durMs: 200, gain: 0.06 * v, type: 'triangle' },
        ]);
        return;
      case 'illegal':
        // Low, short buzz.
        playTone({ freq: 140, freq2: 100, durMs: 140, gain: 0.10 * v, type: 'square' });
        return;
      case 'win': {
        // 4-note fanfare: C E G C', staggered 90ms apart.
        const c = getCtx();
        if (!c) return;
        const notes = [523.25, 659.25, 783.99, 1046.5];
        notes.forEach((f, i) => {
          setTimeout(() => {
            playChord([
              { freq: f, durMs: 220, gain: 0.14 * v, type: 'triangle' },
              { freq: f * 2, durMs: 180, gain: 0.06 * v, type: 'sine' },
            ]);
          }, i * 95);
        });
        return;
      }
    }
  } catch {}
}
