import type { Card, Game, Position, Rank, Step, Suit } from './types.js';
import { suitToFoundationIdx } from './helpers.js';

/** Apply a single atomic step to a game, returning a new immutable game. */
export function applyStep(g: Game, step: Step): Game {
  const { from, to, card } = step;

  // Remove from source.
  let cascades = g.cascades.map((c) => [...c]) as Card[][];
  let cells = [...g.cells] as (Card | null)[];
  let foundations = [...g.foundations] as (0 | Rank)[];

  // Remove card from source.
  if (from.kind === 'cascade') {
    const col = cascades[from.index]!;
    const row = from.row ?? col.length - 1;
    col.splice(row, 1);
  } else if (from.kind === 'cell') {
    cells[from.index] = null;
  } else if (from.kind === 'foundation') {
    // Moving from foundation: decrement the top rank.
    foundations[from.index] = (foundations[from.index]! - 1) as 0 | Rank;
  }

  // Place card at destination.
  if (to.kind === 'cascade') {
    cascades[to.index]!.push(card);
  } else if (to.kind === 'cell') {
    cells[to.index] = card;
  } else if (to.kind === 'foundation') {
    foundations[to.index] = card.rank;
  }

  return {
    ...g,
    cascades: cascades.map((c) => Object.freeze(c)) as Game['cascades'],
    cells: Object.freeze(cells) as Game['cells'],
    foundations: Object.freeze(foundations) as Game['foundations'],
  };
}

/** Reverse a step (for undo). */
export function reverseStep(s: Step): Step {
  return { from: s.to, to: s.from, card: s.card };
}
