import { useEffect, useState } from 'react';
import type { Rank, Suit } from '../../engine/index.js';
import { Card } from './Card.js';
import { bus } from '../../lib/bus.js';

const SUIT_NAMES: Record<0 | 1 | 2 | 3, string> = {
  0: 'Clubs', 1: 'Diamonds', 2: 'Hearts', 3: 'Spades',
};
const SUIT_GLYPHS: Record<0 | 1 | 2 | 3, string> = {
  0: '♣', 1: '♦', 2: '♥', 3: '♠',
};
const SUITS: Suit[] = ['C', 'D', 'H', 'S'];

interface FoundationProps {
  index: 0 | 1 | 2 | 3;
  top: 0 | Rank;
  legalTarget?: boolean;
  onTap: () => void;
}

export function Foundation({ index, top, legalTarget, onTap }: FoundationProps) {
  const suit = SUITS[index]!;
  const label = top === 0
    ? `${SUIT_NAMES[index]} foundation, empty`
    : `${SUIT_NAMES[index]} foundation, top rank ${top}`;

  const [popClass, setPopClass] = useState('');
  const [trail, setTrail] = useState(false);

  useEffect(() => {
    const off = bus.on('moveApplied', ({ steps, supermove }) => {
      // Auto-foundation moves arrive as separate non-supermove `moveApplied` events
      // emitted after the player's primary move. They typically come as a single
      // step OR a sequence of single-card→foundation steps fired together.
      // We trail when the move lands here AND the move is plausibly an auto-step:
      //   no supermove flag AND the from-position was a cascade tail / cell.
      let lands = false;
      let isAuto = !supermove;
      for (const step of steps) {
        if (step.to.kind === 'foundation' && step.to.index === index) {
          lands = true;
          const cls = step.card.rank === 13 ? 'is-king-pop' : 'is-pop';
          setPopClass(cls);
          setTimeout(() => setPopClass(''), cls === 'is-king-pop' ? 720 : 280);
          break;
        }
      }
      if (lands && isAuto && steps.length > 1) {
        // Series of auto-flushes: pulse the trail.
        setTrail(true);
        setTimeout(() => setTrail(false), 480);
      }
    });
    return off;
  }, [index]);

  const cls = [
    'ms-foundation',
    legalTarget ? 'is-target' : '',
    popClass,
    trail ? 'is-auto-trail' : '',
  ].filter(Boolean).join(' ');

  return (
    <div
      className={cls}
      data-foundation={index}
      onClick={onTap}
      role="button"
      tabIndex={0}
      aria-label={label}
      onKeyDown={(e) => e.key === 'Enter' && onTap()}
    >
      {top === 0 ? (
        <span className="ms-foundation-glyph" aria-hidden>{SUIT_GLYPHS[index]}</span>
      ) : (
        <Card
          card={{ rank: top as Rank, suit }}
        />
      )}
    </div>
  );
}
