import { useEffect, useState } from 'react';

function formatTime(ms: number): string {
  const s = Math.floor(ms / 1000);
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  if (h > 0) return `${h}:${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
  return `${m}:${String(sec).padStart(2, '0')}`;
}

interface TimerProps {
  running: boolean;
  startedAt: number | null;
  pausedElapsedMs?: number;
}

export function Timer({ running, startedAt, pausedElapsedMs = 0 }: TimerProps) {
  const [, setTick] = useState(0);

  useEffect(() => {
    if (!running || !startedAt) return;
    const id = setInterval(() => setTick((t) => t + 1), 1000);
    return () => clearInterval(id);
  }, [running, startedAt]);

  // While running, derive elapsed live from startedAt (which PauseButton adjusts on resume).
  // While paused, show the frozen snapshot passed from Hud.
  const elapsedMs = running && startedAt ? Date.now() - startedAt : pausedElapsedMs;

  return (
    <span className="ce-hud-timer" aria-label={`Elapsed time: ${formatTime(elapsedMs)}`}>
      {formatTime(elapsedMs)}
    </span>
  );
}
