const VOL_KEY = 'bilko_cellar_volume';
const MUTE_KEY = 'bilko_cellar_muted';
const HAPTIC_KEY = 'bilko_cellar_haptics';

export interface FeedbackSettings {
  volume: number;
  muted: boolean;
  haptics: boolean;
}

export function readSettings(): FeedbackSettings {
  try {
    return {
      volume: parseFloat(localStorage.getItem(VOL_KEY) ?? '0.6'),
      muted: (localStorage.getItem(MUTE_KEY) ?? 'false') === 'true',
      haptics: (localStorage.getItem(HAPTIC_KEY) ?? 'true') === 'true',
    };
  } catch {
    return { volume: 0.6, muted: false, haptics: true };
  }
}

export function writeSettings(s: Partial<FeedbackSettings>): void {
  try {
    if (s.volume !== undefined) localStorage.setItem(VOL_KEY, String(s.volume));
    if (s.muted !== undefined) localStorage.setItem(MUTE_KEY, String(s.muted));
    if (s.haptics !== undefined) localStorage.setItem(HAPTIC_KEY, String(s.haptics));
  } catch {}
}
