import { useEffect, useState } from 'react';
import { useGameStore } from '../../state/store.js';
import { readHistory } from '../../state/history.js';
import { bus } from '../../lib/bus.js';
import { dayOfWeekBracket, bracketLabel } from './bracket.js';
import { CalendarDialog } from './CalendarDialog.js';
import { isoDateLocal } from '../../state/utils.js';
import { readDailyCache } from '../../state/daily-cache.js';
import './daily.css';

function formatLocalDate(d: Date): string {
  return d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
}

// Build a list of the previous 14 days + today.
// O(15) — trivial, runs once per render.
function recentDays(today: Date, count: number): Date[] {
  const out: Date[] = [];
  for (let i = count - 1; i >= 0; i--) {
    out.push(new Date(today.getTime() - i * 86_400_000));
  }
  return out;
}

interface StreakStripProps {
  todayIso: string;
  completedDays: ReadonlyArray<string>;
}

function StreakStrip({ todayIso, completedDays }: StreakStripProps) {
  const today = new Date(todayIso + 'T00:00:00');
  const days = recentDays(today, 14);
  const set = new Set(completedDays);
  return (
    <div className="ce-streak-strip" role="list" aria-label="Recent daily completions">
      {days.map((d) => {
        const iso = isoDateLocal(d);
        const won = set.has(iso);
        const isToday = iso === todayIso;
        return (
          <span
            key={iso}
            role="listitem"
            className={
              'ce-streak-dot' +
              (won ? ' is-won' : '') +
              (isToday ? ' is-today' : '') +
              (!won && !isToday ? ' is-missed' : '')
            }
            aria-label={`${iso}${won ? ', solved' : isToday ? ', today' : ', missed'}`}
            title={iso}
          />
        );
      })}
    </div>
  );
}

export function DailyCard() {
  const today = isoDateLocal(new Date());
  const bracket = dayOfWeekBracket(new Date());
  const game = useGameStore((s) => s.game);
  const status = useGameStore((s) => s.status);
  const daily = useGameStore((s) => s.daily);
  const moves = useGameStore((s) => s.moves);
  const [calOpen, setCalOpen] = useState(false);
  const [history, setHistory] = useState(() => readHistory());

  useEffect(() => {
    const off = bus.on('gameWon', () => setHistory(readHistory()));
    return off;
  }, []);

  const todayWon = history.daily.completedDays.includes(today);
  const todayInProgress = daily && status === 'playing';
  // Daily deal number — read from cache (warm when the user has clicked Play
  // at least once today). Avoids running the solver synchronously on first
  // paint.  O(1) — single localStorage read.
  const dailyCached = readDailyCache(today);
  const dailyDealNumber = dailyCached?.game.dealNumber ?? 0;

  return (
    <section className="ce-daily" aria-label="Daily Cellar">
      <header className="ce-daily-header">
        <span className="ce-daily-eyebrow">Today's Cellar</span>
        <span className="ce-daily-date">{formatLocalDate(new Date())}</span>
        <span className={`ce-daily-pill ce-daily-pill-${bracket}`}>{bracketLabel(bracket)}</span>
      </header>
      <div className="ce-daily-status">
        {todayWon ? (
          <span>Solved · 🔥 streak: {history.daily.streak}</span>
        ) : todayInProgress ? (
          <span>Resume — {moves} moves so far</span>
        ) : (
          <span>One verified-winnable deal a day. Same for every player.</span>
        )}
      </div>
      {dailyDealNumber > 0 && (
        <div className="ce-daily-deal-no" aria-label={`Daily deal number ${dailyDealNumber}`}>
          Deal #{String(dailyDealNumber).padStart(5, '0')}
        </div>
      )}
      <StreakStrip todayIso={today} completedDays={history.daily.completedDays} />
      <div className="ce-daily-actions">
        <button
          className="ce-daily-primary"
          onClick={() => bus.emit('newDealRequested', { daily: true })}
        >
          {todayWon ? 'Play again' : todayInProgress ? 'Resume' : 'Play'}
        </button>
        <button className="ce-daily-secondary" onClick={() => setCalOpen(true)}>
          Calendar
        </button>
      </div>
      {calOpen && <CalendarDialog onClose={() => setCalOpen(false)} history={history} />}
    </section>
  );
}
