/** The 8 famously-unsolvable Microsoft FreeCell deals. */
export const KNOWN_UNSOLVABLE_MS_DEALS = [
  11982, 146692, 186216, 455889, 495505, 512118, 517776, 781948,
] as const;

export function isKnownUnsolvable(dealNumber: number): boolean {
  return (KNOWN_UNSOLVABLE_MS_DEALS as readonly number[]).includes(dealNumber);
}
