import type { DifficultyBracket } from '../../solver/index.js';

export function dayOfWeekBracket(date: Date): DifficultyBracket {
  const dow = date.getDay(); // 0=Sun, 1=Mon, ..., 6=Sat (local)
  if (dow === 1 || dow === 2) return 'easy';
  if (dow === 3 || dow === 4) return 'standard';
  if (dow === 5) return 'hard';
  return 'master'; // 0 (Sun) and 6 (Sat)
}

export function bracketLabel(b: DifficultyBracket): string {
  return ({ easy: 'Easy', standard: 'Standard', hard: 'Hard', master: 'Master', unsolvable: 'Unsolvable' } as const)[b];
}
