import type { Card, Game, Move, MoveResult, Position, Rank, Step } from './types.js';
import { isLegalMove } from './legal.js';
import { resolveSupermove } from './supermove.js';
import { applyStep, reverseStep } from './apply.js';
import { suitToFoundationIdx } from './helpers.js';

function cardAt(g: Game, pos: Position): Card | null {
  if (pos.kind === 'cascade') {
    const c = g.cascades[pos.index];
    if (!c) return null;
    const row = pos.row ?? c.length - 1;
    return c[row] ?? null;
  }
  if (pos.kind === 'cell') {
    return g.cells[pos.index] ?? null;
  }
  if (pos.kind === 'foundation') {
    const rank = g.foundations[pos.index];
    if (!rank) return null;
    const suits = ['C', 'D', 'H', 'S'] as const;
    return { rank: rank as Rank, suit: suits[pos.index]! };
  }
  return null;
}

export function applyMove(g: Game, from: Position, to: Position): MoveResult {
  if (!isLegalMove(g, from, to)) {
    return { ok: false, game: g, reason: 'illegal' };
  }

  const headCard = cardAt(g, from);
  if (!headCard) return { ok: false, game: g, reason: 'no_card' };

  let steps: Step[];

  if (from.kind === 'cascade' && to.kind === 'cascade') {
    const srcCasc = g.cascades[from.index]!;
    const srcRow = from.row ?? srcCasc.length - 1;
    const runLen = srcCasc.length - srcRow;

    if (runLen > 1) {
      const resolved = resolveSupermove(g, from.index, srcRow, to.index);
      if (!resolved) return { ok: false, game: g, reason: 'cap_exceeded' };
      steps = resolved;
    } else {
      steps = [{ from: { kind: 'cascade', index: from.index, row: srcRow }, to, card: headCard }];
    }
  } else {
    // Single-card move: cell↔cascade, foundation, etc.
    const effectiveFrom: Position = from.kind === 'cascade'
      ? { kind: 'cascade', index: from.index, row: g.cascades[from.index]!.length - 1 }
      : from;
    steps = [{ from: effectiveFrom, to, card: headCard }];
  }

  // Apply each step in order.
  let cur = g;
  for (const s of steps) {
    cur = applyStep(cur, s);
  }

  const supermove = steps.length > 1;
  const move: Move = { from, to, card: headCard, steps, supermove };
  return {
    ok: true,
    game: { ...cur, history: [...cur.history, move] },
    move,
  };
}

export function undo(g: Game): MoveResult {
  const last = g.history[g.history.length - 1];
  if (!last) return { ok: false, game: g, reason: 'history_empty' };

  // Reverse each Step in reverse order.
  let cur = g;
  for (let i = last.steps.length - 1; i >= 0; i--) {
    cur = applyStep(cur, reverseStep(last.steps[i]!));
  }

  return {
    ok: true,
    game: { ...cur, history: g.history.slice(0, -1) },
    move: last,
  };
}
