import { useGameStore } from '../../state/store.js';
import { autoFlushSteps, applyMove } from '../../engine/index.js';
import { bus } from '../../lib/bus.js';
import { IconAutoComplete } from './icons.js';

export function AutoCompleteButton() {
  const onClick = () => {
    const s = useGameStore.getState();
    const steps = autoFlushSteps(s.game);
    if (!steps.length) return;

    let cur = s.game;
    for (const st of steps) {
      const r = applyMove(cur, st.from, st.to);
      if (r.ok) cur = r.game;
    }

    const endedAt = Date.now();
    const timeMs = endedAt - (s.startedAt ?? endedAt);
    const newMoves = s.moves + steps.length;

    useGameStore.setState({
      game: cur,
      moves: newMoves,
      status: 'won',
      endedAt,
      canAutoFlush: false,
    });

    bus.emit('moveApplied', { steps, supermove: false });
    bus.emit('gameWon', {
      dealNumber: cur.dealNumber,
      daily: s.daily,
      timeMs,
      moves: newMoves,
    });
  };

  return (
    <button
      className="ce-hud-btn ce-hud-btn-primary"
      onClick={onClick}
      aria-label="Auto-complete to foundations"
    >
      <IconAutoComplete />
      <span className="ce-hud-btn-label">Auto-complete</span>
    </button>
  );
}
