/** Returns YYYY-MM-DD in the local timezone. */
export function isoDateLocal(d: Date): string {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

/** Returns ISO 8601 week string YYYY-Www in local timezone. */
export function isoWeek(d: Date): string {
  // ISO week: Mon is first day. Week 1 contains the first Thursday of the year.
  const target = new Date(d.valueOf());
  const dayNr = (d.getDay() + 6) % 7; // 0=Mon, ..., 6=Sun
  target.setDate(target.getDate() - dayNr + 3);
  const firstThursday = target.valueOf();
  target.setMonth(0, 1);
  if (target.getDay() !== 4) {
    target.setMonth(0, 1 + ((4 - target.getDay() + 7) % 7));
  }
  const weekNum = 1 + Math.ceil((firstThursday - target.valueOf()) / 604800000);
  return `${d.getFullYear()}-W${String(weekNum).padStart(2, '0')}`;
}

export function countMissedDaysBetween(aIso: string, bIso: string): number {
  const a = new Date(aIso + 'T00:00:00');
  const b = new Date(bIso + 'T00:00:00');
  const diff = Math.round((b.getTime() - a.getTime()) / 86_400_000);
  return Math.max(0, diff - 1);
}
