import type { CellarHistory } from './store.js';
import type { DifficultyBracket } from '../solver/index.js';
import { isoDateLocal, isoWeek, countMissedDaysBetween } from './utils.js';

const HIST_KEY = 'bilko_cellar_history_v1';
export const SAVE_KEY_EXPORT = 'bilko_cellar_save_v1';

export function readHistory(): CellarHistory {
  try {
    const raw = localStorage.getItem(HIST_KEY);
    if (!raw) return blank();
    const parsed = JSON.parse(raw) as CellarHistory;
    if (parsed.schemaVersion === 1) return parsed;
  } catch {}
  return blank();
}

export function writeHistory(h: CellarHistory): void {
  try {
    localStorage.setItem(HIST_KEY, JSON.stringify(h));
  } catch {}
}

export function recordWin(opts: {
  dealNumber: number;
  daily: boolean;
  bracket: DifficultyBracket;
  timeMs: number;
  moves: number;
}): void {
  const h = readHistory();
  h.totalWins += 1;

  const prevBestTime = h.bestTimeMs[opts.bracket];
  if (prevBestTime === undefined || opts.timeMs < prevBestTime) {
    h.bestTimeMs[opts.bracket] = opts.timeMs;
  }
  const prevBestMoves = h.bestMoves[opts.bracket];
  if (prevBestMoves === undefined || opts.moves < prevBestMoves) {
    h.bestMoves[opts.bracket] = opts.moves;
  }

  const prevDeal = h.playedDeals[opts.dealNumber];
  h.playedDeals[opts.dealNumber] = {
    wins: (prevDeal?.wins ?? 0) + 1,
    bestTimeMs: Math.min(prevDeal?.bestTimeMs ?? Infinity, opts.timeMs),
    bestMoves: Math.min(prevDeal?.bestMoves ?? Infinity, opts.moves),
    lastPlayed: isoDateLocal(new Date()),
  };

  if (opts.daily) {
    const today = isoDateLocal(new Date());
    advanceStreak(h, today);
  }

  writeHistory(h);
}

function advanceStreak(h: CellarHistory, todayIso: string): void {
  const yesterdayIso = isoDateLocal(new Date(Date.now() - 86_400_000));
  const last = h.daily.lastWonIsoDate;
  const week = isoWeek(new Date());

  // Reset weekly freeze if week rolled over.
  if (h.daily.streakFreezes.weekOf !== week) {
    h.daily.streakFreezes = { availableThisWeek: 1, weekOf: week };
  }

  if (last === todayIso) return; // already counted
  if (last === yesterdayIso) {
    h.daily.streak += 1;
  } else if (
    last !== null &&
    countMissedDaysBetween(last, todayIso) === 1 &&
    h.daily.streakFreezes.availableThisWeek === 1
  ) {
    h.daily.streakFreezes.availableThisWeek = 0;
    h.daily.streak += 1;
  } else {
    h.daily.streak = 1;
  }

  h.daily.lastWonIsoDate = todayIso;
  if (!h.daily.completedDays.includes(todayIso)) {
    h.daily.completedDays.push(todayIso);
  }
  h.daily.longestStreak = Math.max(h.daily.longestStreak, h.daily.streak);
}

export function clearInProgressSave(): void {
  try {
    localStorage.removeItem(SAVE_KEY_EXPORT);
  } catch {}
}

function blank(): CellarHistory {
  return {
    schemaVersion: 1,
    bestTimeMs: {},
    bestMoves: {},
    totalWins: 0,
    totalDeals: 0,
    playedDeals: {},
    daily: {
      streak: 0,
      longestStreak: 0,
      lastWonIsoDate: null,
      streakFreezes: { availableThisWeek: 1, weekOf: isoWeek(new Date()) },
      completedDays: [],
    },
  };
}
