import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus.js';
import { useGameStore } from '../../state/store.js';
import { readHistory } from '../../state/history.js';
import { ShareButton } from '../daily/index.js';
import { fireConfetti } from '../animations/confetti.js';
import { isoDateLocal } from '../../state/utils.js';
import './win.css';

function formatMmSs(ms: number): string {
  const s = Math.floor(ms / 1000);
  const m = Math.floor(s / 60);
  const sec = s % 60;
  return `${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
}

const prefersReducedMotion = () =>
  typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

export function WinModal() {
  const [visible, setVisible] = useState(false);
  const [winData, setWinData] = useState<{
    timeMs: number; moves: number; pb: { time: boolean; moves: boolean };
  } | null>(null);

  const game = useGameStore((s) => s.game);
  const daily = useGameStore((s) => s.daily);
  const bracket = useGameStore((s) => s.bracket);

  useEffect(() => {
    const off = bus.on('gameWon', ({ timeMs, moves: m }) => {
      const h = readHistory();
      const prevBestTime = h.bestTimeMs[bracket];
      const prevBestMoves = h.bestMoves[bracket];
      const isTimePb = prevBestTime === undefined || timeMs < prevBestTime;
      const isMovesPb = prevBestMoves === undefined || m < prevBestMoves;

      setWinData({ timeMs, moves: m, pb: { time: isTimePb, moves: isMovesPb } });
      setVisible(true);

      if ((isTimePb || isMovesPb) && !prefersReducedMotion()) {
        fireConfetti();
      }
    });
    return off;
  }, [bracket]);

  // ESC to dismiss
  useEffect(() => {
    if (!visible) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setVisible(false);
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [visible]);

  if (!visible || !winData) return null;

  const { timeMs, moves, pb } = winData;
  const today = isoDateLocal(new Date());
  const history = readHistory();
  const streak = history.daily.streak;
  const isPb = pb.time || pb.moves;
  const pbLabel = pb.time && pb.moves ? ' (time + moves)' : pb.time ? ' time' : ' moves';

  return (
    <div
      className="ce-win-backdrop"
      onClick={() => setVisible(false)}
      role="dialog"
      aria-modal="true"
      aria-label="Game won"
    >
      <div className="ce-win" onClick={(e) => e.stopPropagation()}>
        <button
          className="ce-win-close"
          aria-label="Close"
          onClick={() => setVisible(false)}
        >
          ×
        </button>
        <h2>Cellar #{String(game.dealNumber).padStart(5, '0')} solved.</h2>
        <p className="ce-win-stats">{formatMmSs(timeMs)} · {moves} mvs</p>
        {daily && streak > 0 && (
          <p className="ce-win-streak">🔥 {streak}-day streak</p>
        )}
        {isPb && (
          <p className="ce-win-pb">
            {prefersReducedMotion() ? '🎉 ' : ''}New personal best{pbLabel}!
          </p>
        )}
        <div className="ce-win-actions">
          {daily ? (
            <ShareButton
              isoDate={today}
              bracket={bracket}
              dealNumber={game.dealNumber}
              timeMs={timeMs}
              moves={moves}
              solverMoves={null}
              streakAlive={streak > 0}
            />
          ) : (
            <button
              onClick={() =>
                navigator.clipboard.writeText(
                  `Cellar #${String(game.dealNumber).padStart(5, '0')} · ${formatMmSs(timeMs)} · ${moves} mvs\nhttps://bilko.run/projects/cellar/?deal=${game.dealNumber}`
                )
              }
            >
              Share this deal
            </button>
          )}
          <button
            onClick={() => {
              bus.emit('newDealRequested', { dealNumber: game.dealNumber });
              setVisible(false);
            }}
          >
            Replay this deal
          </button>
          <button
            className="ce-win-primary"
            onClick={() => {
              bus.emit('newDealRequested', {});
              setVisible(false);
            }}
          >
            Play another
          </button>
        </div>
      </div>
    </div>
  );
}
