import { useEffect } from 'react';
import { useGameStore } from '../../state/store.js';
import { DealNumber } from './DealNumber.js';
import { Timer } from './Timer.js';
import { MoveCount } from './MoveCount.js';
import { UndoButton } from './UndoButton.js';
import { RestartButton } from './RestartButton.js';
import { PauseButton } from './PauseButton.js';
import { SettingsCog } from './SettingsCog.js';
import { AutoCompleteButton } from './AutoCompleteButton.js';
import { HelpButton } from './HelpButton.js';
import './hud.css';

export function Hud() {
  const game = useGameStore((s) => s.game);
  const status = useGameStore((s) => s.status);
  const startedAt = useGameStore((s) => s.startedAt);
  const pausedAt = useGameStore((s) => s.pausedAt);
  const moves = useGameStore((s) => s.moves);
  const canAutoFlush = useGameStore((s) => s.canAutoFlush);

  // Elapsed at the moment of pause — frozen snapshot for the timer display.
  const pausedElapsedMs =
    status === 'paused' && pausedAt !== null && startedAt !== null
      ? pausedAt - startedAt
      : 0;

  // Stamp the document root so CSS can veil the board while paused.
  useEffect(() => {
    document.documentElement.dataset.gameStatus = status;
    return () => { delete document.documentElement.dataset.gameStatus; };
  }, [status]);

  return (
    <div className="ce-hud" role="toolbar" aria-label="Game controls">
      <DealNumber n={game.dealNumber} />
      <Timer running={status === 'playing'} startedAt={startedAt} pausedElapsedMs={pausedElapsedMs} />
      <MoveCount n={moves} />
      <span className="ce-hud-spacer" />
      {canAutoFlush && status === 'playing' && <AutoCompleteButton />}
      <UndoButton disabled={game.history.length === 0 || status !== 'playing'} />
      <RestartButton moves={moves} />
      <PauseButton paused={status === 'paused'} />
      <HelpButton />
      <SettingsCog />
    </div>
  );
}
