import { lazy, Suspense, useState } from 'react';
import { ThemeSwitcher } from '../ThemeSwitcher.js';

// Lazy-load StatsPanel — heavy panel, only mounted when user clicks "View stats".
const StatsPanel = lazy(() =>
  import('../../stats/index.js').then((m) => ({ default: m.StatsPanel })),
);

export function SettingsPanel() {
  const [statsOpen, setStatsOpen] = useState(false);

  return (
    <div className="ce-settings">
      <section>
        <h3>Theme</h3>
        <ThemeSwitcher />
      </section>
      <section>
        <h3>Sound</h3>
        <div className="ce-settings-row">
          <span>Sound</span>
          <SoundToggle />
        </div>
        <div className="ce-settings-row">
          <span>Volume</span>
          <VolumeSlider />
        </div>
        <div className="ce-settings-row">
          <span>Haptics</span>
          <HapticsToggle />
        </div>
      </section>
      <section>
        <h3>Animation</h3>
        <div className="ce-settings-row">
          <span>Supermove steps</span>
          <SupermoveToggle />
        </div>
        <div className="ce-settings-row">
          <span>Autoflush speed</span>
          <AutoflushSpeed />
        </div>
      </section>
      <section>
        <h3>Game rules</h3>
        <div className="ce-settings-row">
          <span>Lock foundation cards</span>
          <FoundationLockToggle />
        </div>
      </section>
      <section>
        <h3>Stats</h3>
        <div className="ce-settings-row">
          <span>Personal stats</span>
          <button
            className="ce-settings-chip"
            onClick={() => setStatsOpen(true)}
            data-testid="cellar-stats-open"
          >
            View
          </button>
        </div>
        <div className="ce-settings-row">
          <span>Reset stats</span>
          <ResetStatsButton />
        </div>
      </section>
      {statsOpen && (
        <Suspense fallback={null}>
          <StatsPanel onClose={() => setStatsOpen(false)} />
        </Suspense>
      )}
    </div>
  );
}

function SoundToggle() {
  const [muted, setMuted] = useState(
    () => localStorage.getItem('bilko_cellar_muted') === 'true',
  );
  return (
    <button
      role="switch"
      aria-checked={!muted}
      className={`ce-settings-chip${!muted ? ' is-active' : ''}`}
      onClick={() => {
        const next = !muted;
        setMuted(next);
        localStorage.setItem('bilko_cellar_muted', String(next));
      }}
    >
      {muted ? 'Off' : 'On'}
    </button>
  );
}

function VolumeSlider() {
  const [vol, setVol] = useState(
    () => parseFloat(localStorage.getItem('bilko_cellar_volume') ?? '0.6'),
  );
  return (
    <input
      type="range"
      min="0"
      max="1"
      step="0.1"
      value={vol}
      aria-label="Volume"
      style={{ width: 80 }}
      onChange={(e) => {
        const next = parseFloat(e.target.value);
        setVol(next);
        localStorage.setItem('bilko_cellar_volume', String(next));
      }}
    />
  );
}

function HapticsToggle() {
  const [on, setOn] = useState(
    () => (localStorage.getItem('bilko_cellar_haptics') ?? 'true') === 'true',
  );
  return (
    <button
      role="switch"
      aria-checked={on}
      className={`ce-settings-chip${on ? ' is-active' : ''}`}
      onClick={() => {
        const next = !on;
        setOn(next);
        localStorage.setItem('bilko_cellar_haptics', String(next));
      }}
    >
      {on ? 'On' : 'Off'}
    </button>
  );
}

function SupermoveToggle() {
  const [on, setOn] = useState(
    () => localStorage.getItem('bilko_cellar_show_supermove_steps') !== 'off',
  );
  return (
    <button
      role="switch"
      aria-checked={on}
      className={`ce-settings-chip${on ? ' is-active' : ''}`}
      onClick={() => {
        const next = !on;
        setOn(next);
        localStorage.setItem('bilko_cellar_show_supermove_steps', next ? 'on' : 'off');
      }}
    >
      {on ? 'On' : 'Off'}
    </button>
  );
}

function AutoflushSpeed() {
  const [speed, setSpeed] = useState(
    () => localStorage.getItem('bilko_cellar_autoflush_speed') ?? '120',
  );
  return (
    <div className="ce-settings-chips" role="radiogroup" aria-label="Autoflush speed">
      {(['50', '120', '240'] as const).map((s) => (
        <button
          key={s}
          role="radio"
          aria-checked={speed === s}
          className={`ce-settings-chip${speed === s ? ' is-active' : ''}`}
          onClick={() => {
            setSpeed(s);
            localStorage.setItem('bilko_cellar_autoflush_speed', s);
          }}
        >
          {s === '50' ? 'Fast' : s === '240' ? 'Slow' : 'Normal'}
        </button>
      ))}
    </div>
  );
}

function FoundationLockToggle() {
  const [locked, setLocked] = useState(
    () => localStorage.getItem('bilko_cellar_foundation_locked') === 'true',
  );
  return (
    <button
      role="switch"
      aria-checked={locked}
      className={`ce-settings-chip${locked ? ' is-active' : ''}`}
      onClick={() => {
        const next = !locked;
        setLocked(next);
        localStorage.setItem('bilko_cellar_foundation_locked', String(next));
      }}
    >
      {locked ? 'Locked' : 'Unlocked'}
    </button>
  );
}

function ResetStatsButton() {
  const [confirming, setConfirming] = useState(false);
  if (confirming) {
    return (
      <div className="ce-settings-chips">
        <button
          className="ce-settings-chip"
          style={{ background: '#dc2626', color: '#fff' }}
          onClick={() => {
            import('../../stats/index.js').then(({ resetStats }) => {
              resetStats();
              setConfirming(false);
            });
          }}
        >
          Confirm
        </button>
        <button className="ce-settings-chip" onClick={() => setConfirming(false)}>
          Cancel
        </button>
      </div>
    );
  }
  return (
    <button className="ce-settings-chip" onClick={() => setConfirming(true)}>
      Reset
    </button>
  );
}
