import type { Card, Game, Position, Rank, Step, Suit } from './types.js';
import { color, suitToFoundationIdx, oppositeColorFoundations } from './helpers.js';
import { applyStep } from './apply.js';

export function isWon(g: Game): boolean {
  // Won if every foundation has a King (rank 13) on top.
  return g.foundations.every((r) => r === 13);
}

export function canAutoFlush(g: Game): boolean {
  // Auto-flush available when the board is orderly enough to sweep.
  // Check: foundations + cascades + cells contain all 52 cards.
  // Also: every cascade is an alternating-color descending run (or empty),
  // AND every cell is empty.
  // Simplified: just check if cells are all empty and we can auto-sweep.
  // In practice: if every remaining card is safely auto-moveable,
  // the board is flushable. We use the 'always' heuristic to test this.
  const testGame: Game = { ...g, settings: { ...g.settings, autoFlushHeuristic: 'always' } };
  const steps = safeAutoMove(testGame);
  if (steps.length === 0) return false;

  // Simulate applying all auto-steps to see if it fully clears.
  let cur: Game = testGame;
  for (const s of steps) {
    cur = applyStep(cur, s);
  }
  return isWon(cur);
}

export function autoFlushSteps(g: Game): Step[] {
  // Run safeAutoMove with 'always' until done.
  const testGame: Game = { ...g, settings: { ...g.settings, autoFlushHeuristic: 'always' } };
  return safeAutoMove(testGame);
}

export function safeAutoMove(g: Game): Step[] {
  if (g.settings.autoFlushHeuristic === 'never') return [];

  const out: Step[] = [];
  let cur = g;
  let progress = true;

  while (progress) {
    progress = false;
    const sources: Array<{ pos: Position; card: Card }> = [];

    for (let i = 0; i < 8; i++) {
      const casc = cur.cascades[i]!;
      const top = casc[casc.length - 1];
      if (top) {
        sources.push({
          pos: { kind: 'cascade', index: i as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row: casc.length - 1 },
          card: top,
        });
      }
    }

    for (let i = 0; i < 4; i++) {
      const c = cur.cells[i];
      if (c) {
        sources.push({ pos: { kind: 'cell', index: i as 0 | 1 | 2 | 3 }, card: c });
      }
    }

    for (const { pos, card } of sources) {
      const foundationIdx = suitToFoundationIdx(card.suit);
      const foundationTop = cur.foundations[foundationIdx]!;
      if (foundationTop !== card.rank - 1) continue;

      if (cur.settings.autoFlushHeuristic === 'safe') {
        if (card.rank > 2) {
          const oppFoundations = oppositeColorFoundations(card.suit, cur.foundations);
          const minOpp = Math.min(oppFoundations[0]!, oppFoundations[1]!);
          if (minOpp < card.rank - 1) continue;
        }
      }

      const step: Step = {
        from: pos,
        to: { kind: 'foundation', index: foundationIdx as 0 | 1 | 2 | 3 },
        card,
      };
      cur = applyStep(cur, step);
      out.push(step);
      progress = true;
      break; // restart scan from new state
    }
  }

  return out;
}
