import { useEffect, useMemo, useRef, useState } from 'react';
import { bus } from '../../lib/bus.js';
import { classifyDifficulty, isKnownUnsolvable, type DifficultyBracket } from '../../solver/index.js';
import { readHistory } from '../../state/history.js';
import { useGameStore } from '../../state/store.js';
import './picker.css';

const BADGE_COPY: Record<number, string> = {
  11982: 'The most famous unsolvable deal in computer game history. (Internet FreeCell Project, 1994.)',
  146692: 'Famously unwinnable. Confirmed by 8+ independent solvers.',
  186216: 'Famously unwinnable. One of the 8 known impossible Microsoft deals.',
  455889: 'Famously unwinnable. One of the 8 known impossible Microsoft deals.',
  495505: 'Famously unwinnable. One of the 8 known impossible Microsoft deals.',
  512118: 'Famously unwinnable. One of the 8 known impossible Microsoft deals.',
  517776: 'Famously unwinnable. One of the 8 known impossible Microsoft deals.',
  781948: 'Famously unwinnable. One of the 8 known impossible Microsoft deals.',
};

function parseDealNumber(s: string): number | null {
  if (!/^[0-9]+$/.test(s)) return null;
  const n = parseInt(s, 10);
  if (!Number.isFinite(n) || n < 1 || n > 1_000_000) return null;
  return n;
}

function bracketLabel(b: DifficultyBracket): string {
  return ({ easy: 'Easy', standard: 'Standard', hard: 'Hard', master: 'Master', unsolvable: 'Unsolvable' } as const)[b];
}

function formatMmSs(ms: number): string {
  if (!Number.isFinite(ms)) return '—';
  const s = Math.floor(ms / 1000);
  return `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;
}

export function DealPickerCard() {
  const [raw, setRaw] = useState('');
  const [bracket, setBracket] = useState<DifficultyBracket | null>(null);
  const [classifying, setClassifying] = useState(false);
  const debounceRef = useRef<number | null>(null);
  const status = useGameStore((s) => s.status);
  const [collapsing, setCollapsing] = useState(false);
  const [gone, setGone] = useState(false);

  useEffect(() => {
    if (status === 'playing') {
      setCollapsing(true);
      const t = window.setTimeout(() => setGone(true), 200);
      return () => clearTimeout(t);
    } else {
      setCollapsing(false);
      setGone(false);
    }
  }, [status]);

  const parsed = parseDealNumber(raw);
  const isValid = parsed !== null;
  const isUnsolvable = parsed !== null && isKnownUnsolvable(parsed);
  const history = useMemo(() => readHistory(), [parsed]);
  const past = parsed != null ? history.playedDeals[parsed] : undefined;

  useEffect(() => {
    if (!isValid) {
      setBracket(null);
      return;
    }
    if (debounceRef.current !== null) clearTimeout(debounceRef.current);
    debounceRef.current = window.setTimeout(() => {
      setClassifying(true);
      const r = classifyDifficulty(parsed!, { nodeCap: 5_000, timeoutMs: 200 });
      setBracket(r.bracket);
      setClassifying(false);
    }, 300);
    return () => {
      if (debounceRef.current !== null) clearTimeout(debounceRef.current);
    };
  }, [parsed, isValid]);

  const onPlay = () => {
    if (!isValid) return;
    bus.emit('newDealRequested', { dealNumber: parsed! });
  };

  const onRandom = () => {
    let n: number;
    do {
      n = 1 + Math.floor(Math.random() * 1_000_000);
    } while (isKnownUnsolvable(n));
    setRaw(String(n));
  };

  if (gone) return null;

  return (
    <section className={`ce-picker${collapsing ? ' ce-picker--out' : ''}`} aria-label="Pick a deal">
      <header className="ce-picker-header">
        <span className="ce-picker-eyebrow">Pick a Deal</span>
      </header>
      <div className="ce-picker-row">
        <input
          type="text"
          inputMode="numeric"
          pattern="[0-9]*"
          placeholder="1..1,000,000"
          value={raw}
          onChange={(e) => setRaw(e.target.value.replace(/[^0-9]/g, '').slice(0, 7))}
          aria-label="Deal number"
          className="ce-picker-input"
        />
        <button className="ce-picker-secondary" onClick={onRandom}>
          Random
        </button>
        <button className="ce-picker-primary" onClick={onPlay} disabled={!isValid}>
          Play
        </button>
      </div>
      {!isValid && raw.length > 0 && (
        <div className="ce-picker-hint">Enter a number from 1 to 1,000,000.</div>
      )}
      {isValid && bracket && (
        <div className="ce-picker-bracket">
          <span className={`ce-picker-pill ce-picker-pill-${bracket}`}>{bracketLabel(bracket)}</span>
          {classifying && <span className="ce-picker-classifying">…</span>}
        </div>
      )}
      {isUnsolvable && parsed && (
        <div className="ce-picker-warn" role="note">
          <span aria-hidden>⚠️</span>
          <span>
            Microsoft deal #{parsed}. {BADGE_COPY[parsed] ?? 'Famously unwinnable.'} We'll deal it anyway — you have been warned.
          </span>
        </div>
      )}
      {past && parsed && (
        <div className="ce-picker-history">
          {past.wins > 0 ? (
            <>You've solved deal #{parsed} {past.wins}× · best <strong>{formatMmSs(past.bestTimeMs)}</strong> · {past.bestMoves} mvs · last played {past.lastPlayed}.</>
          ) : (
            <>You started deal #{parsed} but didn't finish · last played {past.lastPlayed}.</>
          )}
        </div>
      )}
      <footer className="ce-picker-footer">
        Same deal number as Microsoft FreeCell, MobilityWare, Green Felt. 50 years of shared puzzle history.
      </footer>
    </section>
  );
}
