import type { Card, Game, Position, Rank, Step } from '../engine/index.js';
import { isWon } from '../engine/index.js';
import { suitToFoundationIdx } from '../engine/helpers.js';
import { hashGame } from './state.js';
import { heuristic } from './heuristic.js';
import { MinHeap } from './minheap.js';

/**
 * Lightweight single-card apply for the solver — skips history, legal check, and supermove.
 * Only handles cascade→cascade (single card), cascade→cell, cascade→foundation,
 * cell→cascade, cell→foundation.
 * O(N) where N = cascade length (due to immutable copy).
 */
function solverApplyStep(g: Game, step: Step): Game {
  const { from, to, card } = step;
  const cascades = g.cascades.map((c) => [...c]) as Card[][];
  const cells = [...g.cells] as (Card | null)[];
  const foundations = [...g.foundations] as (0 | Rank)[];

  if (from.kind === 'cascade') {
    cascades[from.index]!.pop(); // always removing bottom card
  } else if (from.kind === 'cell') {
    cells[from.index] = null;
  }

  if (to.kind === 'cascade') {
    cascades[to.index]!.push(card);
  } else if (to.kind === 'cell') {
    cells[to.index] = card;
  } else if (to.kind === 'foundation') {
    foundations[to.index] = card.rank;
  }

  return { ...g, cascades: cascades as Game['cascades'], cells: cells as Game['cells'], foundations: foundations as Game['foundations'], history: [] };
}

/**
 * Pruned move generator for the solver — single-card moves only.
 * Moves only the bottom card of each cascade + free cells.
 * Supermoves decompose into individual single-card moves, so this is complete.
 * O(C*(C+F+4)) where C=8 cascades, F=4 free cells.
 */
function solverMoves(g: Game): Array<{ from: Position; to: Position; card: Card }> {
  const result: Array<{ from: Position; to: Position; card: Card }> = [];

  const { cascades, cells, foundations } = g;
  const emptyCellCount = cells.filter((c) => c === null).length;

  // Iterate sources: bottom of each cascade + occupied cells.
  const sources: Array<{ pos: Position; card: Card }> = [];
  for (let i = 0; i < 8; i++) {
    const c = cascades[i]!;
    if (c.length > 0) {
      sources.push({ pos: { kind: 'cascade', index: i as 0|1|2|3|4|5|6|7, row: c.length - 1 }, card: c[c.length - 1]! });
    }
  }
  for (let i = 0; i < 4; i++) {
    const card = cells[i];
    if (card != null) {
      sources.push({ pos: { kind: 'cell', index: i as 0|1|2|3 }, card });
    }
  }

  for (const { pos: from, card } of sources) {
    const fromCascIdx = from.kind === 'cascade' ? from.index : -1;

    // To foundation (always try — O(1) check).
    const fi = suitToFoundationIdx(card.suit);
    if (foundations[fi] === card.rank - 1) {
      result.push({ from, to: { kind: 'foundation', index: fi as 0|1|2|3 }, card });
    }

    // To cascades.
    for (let ci = 0; ci < 8; ci++) {
      if (ci === fromCascIdx) continue;
      const dst = cascades[ci]!;
      if (dst.length === 0) {
        // Move to empty cascade (only if there are other empty cascades or free cells available
        // to avoid pointless transfers; include anyway for solver completeness).
        result.push({ from, to: { kind: 'cascade', index: ci as 0|1|2|3|4|5|6|7, row: 0 }, card });
      } else {
        const top = dst[dst.length - 1]!;
        const topColor = top.suit === 'D' || top.suit === 'H' ? 'r' : 'b';
        const cardColor = card.suit === 'D' || card.suit === 'H' ? 'r' : 'b';
        if (top.rank === card.rank + 1 && topColor !== cardColor) {
          result.push({ from, to: { kind: 'cascade', index: ci as 0|1|2|3|4|5|6|7, row: 0 }, card });
        }
      }
    }

    // To free cells (only cascade sources, not cell→cell).
    if (from.kind === 'cascade' && emptyCellCount > 0) {
      for (let ci = 0; ci < 4; ci++) {
        if (cells[ci] === null) {
          result.push({ from, to: { kind: 'cell', index: ci as 0|1|2|3 }, card });
          break; // cells are interchangeable — only generate one cell move per card
        }
      }
    }
  }

  return result;
}

export interface SolveOpts {
  nodeCap?: number;   // default 200_000
  timeoutMs?: number; // default 6_000
}

export interface SolveResult {
  solvable: boolean;
  exhausted: boolean;
  solution?: Step[];
  nodes: number;
  ms: number;
}

interface Node {
  game: Game;
  parent: Node | null;
  parentStep: Step | null;
  g: number; // move depth
  f: number; // g + heuristic
}

export function solve(g: Game, opts: SolveOpts = {}): SolveResult {
  const t0 = Date.now();
  const cap = opts.nodeCap ?? 200_000;
  const deadline = t0 + (opts.timeoutMs ?? 6_000);

  const open = new MinHeap<Node>((a, b) => a.f - b.f);
  const seen = new Map<string, number>(); // hash → best g

  const root: Node = { game: g, parent: null, parentStep: null, g: 0, f: heuristic(g) };
  open.push(root);
  seen.set(hashGame(g), 0);

  let nodes = 0;

  while (open.size > 0 && nodes < cap && Date.now() < deadline) {
    const cur = open.pop()!;
    nodes += 1;

    if (isWon(cur.game)) {
      // Reconstruct solution.
      const out: Step[] = [];
      let n: Node | null = cur;
      while (n && n.parentStep) {
        out.unshift(n.parentStep);
        n = n.parent;
      }
      return { solvable: true, exhausted: false, solution: out, nodes, ms: Date.now() - t0 };
    }

    for (const { from, to, card } of solverMoves(cur.game)) {
      const step: Step = { from, to, card };
      const next = solverApplyStep(cur.game, step);

      const nextG = cur.g + 1;
      const h = hashGame(next);
      const prev = seen.get(h);
      if (prev !== undefined && prev <= nextG) continue;
      seen.set(h, nextG);

      open.push({
        game: next,
        parent: cur,
        parentStep: step,
        g: nextG,
        f: nextG + heuristic(next),
      });
    }
  }

  const exhausted = nodes >= cap || Date.now() >= deadline;
  return { solvable: false, exhausted, nodes, ms: Date.now() - t0 };
}
