import { useEffect, type ReactNode } from 'react';
import { attachAutosave, tryHydrateOnBoot } from '../state/persistence.js';
import { evictOldDailyCaches } from '../state/daily-cache.js';

let booted = false;

export function EngineSlot({ children }: { children?: ReactNode }) {
  useEffect(() => {
    if (booted) return;
    booted = true;
    tryHydrateOnBoot();
    attachAutosave();
    evictOldDailyCaches();
  }, []);
  return <>{children}</>;
}
