import type { Suit as SuitType } from '../../engine/index.js';

// Minimal SVG suit pips. Vector renders crisply at any size.
// All paths fit a 24×24 viewBox; we render at `1em` so they scale with rank font.
// Time/space: O(1) per render.

interface SuitProps {
  suit: SuitType;
  /** Optional className for custom positioning. */
  className?: string;
  /** Render size in CSS units. Defaults to inherit from parent. */
  size?: string;
}

const PATHS: Record<SuitType, JSX.Element> = {
  S: (
    <path d="M12 2 C 8 8 3 11 3 15 C 3 18 5 20 7.5 20 C 9 20 10.5 19.2 11 18 L 10 22 L 14 22 L 13 18 C 13.5 19.2 15 20 16.5 20 C 19 20 21 18 21 15 C 21 11 16 8 12 2 Z" />
  ),
  C: (
    <path d="M12 3 C 9.8 3 8 4.8 8 7 C 8 7.7 8.2 8.4 8.5 9 C 7 9 5 10.6 5 12.8 C 5 15 6.8 16.6 9 16.6 C 10 16.6 10.9 16.2 11.5 15.6 L 10 22 L 14 22 L 12.5 15.6 C 13.1 16.2 14 16.6 15 16.6 C 17.2 16.6 19 15 19 12.8 C 19 10.6 17 9 15.5 9 C 15.8 8.4 16 7.7 16 7 C 16 4.8 14.2 3 12 3 Z" />
  ),
  H: (
    <path d="M12 21 C 12 21 3 14.6 3 8.6 C 3 5.5 5.2 3 8 3 C 9.8 3 11.2 4 12 5.3 C 12.8 4 14.2 3 16 3 C 18.8 3 21 5.5 21 8.6 C 21 14.6 12 21 12 21 Z" />
  ),
  D: (
    <path d="M12 2 L 21 12 L 12 22 L 3 12 Z" />
  ),
};

export function Suit({ suit, className, size }: SuitProps) {
  return (
    <svg
      viewBox="0 0 24 24"
      className={`ms-card-suit${className ? ' ' + className : ''}`}
      style={size ? { width: size, height: size } : undefined}
      aria-hidden
      focusable="false"
    >
      {PATHS[suit]}
    </svg>
  );
}
