import type { Card as CardType, Position } from '../../engine/index.js';
import { cardName } from '../../engine/index.js';
import { Card } from './Card.js';

interface CellProps {
  index: 0 | 1 | 2 | 3;
  card: CardType | null;
  selected?: boolean;
  legalTarget?: boolean;
  onTap: () => void;
}

export function Cell({ index, card, selected, legalTarget, onTap }: CellProps) {
  return (
    <div
      className={`ms-cell${selected ? ' is-selected' : ''}${legalTarget ? ' is-target' : ''}`}
      data-cell={index}
      onClick={onTap}
      role="button"
      tabIndex={0}
      aria-label={card ? `Free cell ${index + 1}, holds ${cardName(card)}` : `Free cell ${index + 1}, empty`}
      onKeyDown={(e) => e.key === 'Enter' && onTap()}
    >
      {card && <Card card={card} selected={selected} />}
    </div>
  );
}
