import { lazy, Suspense } from 'react';
import type { Card as CardType } from '../../engine/index.js';
import { cardName } from '../../engine/index.js';
import { Suit } from './Suit.js';

// Court cards (J/Q/K) get an illustrated decoration — lazy-loaded to keep the
// main bundle slim (court decals only mount when a face card actually renders).
const CourtFace = lazy(() =>
  import('./CourtFace.js').then((m) => ({ default: m.CourtFace })),
);

interface CardProps {
  card: CardType;
  lifted?: boolean;
  selected?: boolean;
  dim?: boolean;
}

function rankText(rank: number): string {
  if (rank === 1) return 'A';
  if (rank === 11) return 'J';
  if (rank === 12) return 'Q';
  if (rank === 13) return 'K';
  return String(rank);
}

export function Card({ card, lifted, selected, dim }: CardProps) {
  const isRed = card.suit === 'D' || card.suit === 'H';
  const text = rankText(card.rank);
  const isCourt = card.rank >= 11;

  return (
    <div
      className={`ms-card${lifted ? ' is-lifted' : ''}${selected ? ' is-selected' : ''}${dim ? ' is-dim' : ''}`}
      style={{ color: isRed ? 'var(--suit-red)' : 'var(--suit-black)' }}
      data-suit-color={isRed ? 'red' : 'black'}
      data-rank={card.rank}
      data-suit={card.suit}
      aria-label={cardName(card)}
    >
      <div className="ms-card-corner ms-card-corner-tl">
        <span className="ms-card-rank">{text}</span>
        <Suit suit={card.suit} />
      </div>
      {isCourt ? (
        <Suspense fallback={<div className="ms-card-court-fallback" aria-hidden>{text}</div>}>
          <CourtFace rank={card.rank as 11 | 12 | 13} suit={card.suit} />
        </Suspense>
      ) : (
        <div className="ms-card-center" aria-hidden>
          <Suit suit={card.suit} className="ms-card-center-pip" />
        </div>
      )}
      <div className="ms-card-corner ms-card-corner-br" aria-hidden>
        <span className="ms-card-rank">{text}</span>
        <Suit suit={card.suit} />
      </div>
    </div>
  );
}
