import { useState } from 'react';
import { legalMoves, type Game, type Position } from '../../engine/index.js';

function positionsEqual(a: Position, b: Position): boolean {
  if (a.kind !== b.kind) return false;
  if (a.index !== b.index) return false;
  if (a.kind === 'cascade' && b.kind === 'cascade') return a.row === b.row;
  return true;
}

export function useSelection(game: Game) {
  const [selection, setSelection] = useState<Position | null>(null);

  function legalTargetsFor(sel: Position | null): Position[] | null {
    if (!sel) return null;
    return legalMoves(game)
      .filter((m) => positionsEqual(m.from, sel))
      .map((m) => m.to);
  }

  return {
    selection,
    select: (p: Position) => setSelection(p),
    clear: () => setSelection(null),
    legalTargetsFor,
  };
}
