import { deal } from '../engine/index.js';
import { solve, type SolveOpts, type SolveResult } from './solve.js';

export function verifyDeal(dealNumber: number, opts: SolveOpts = {}): SolveResult {
  return solve(deal(dealNumber), opts);
}

export type DifficultyBracket = 'easy' | 'standard' | 'hard' | 'master' | 'unsolvable';

export function classifyDifficulty(
  dealNumber: number,
  opts: SolveOpts = {}
): { bracket: DifficultyBracket; nodes: number } {
  const r = solve(deal(dealNumber), opts);
  if (!r.solvable) return { bracket: 'unsolvable', nodes: r.nodes };
  if (r.nodes < 500) return { bracket: 'easy', nodes: r.nodes };
  if (r.nodes < 5_000) return { bracket: 'standard', nodes: r.nodes };
  if (r.nodes < 50_000) return { bracket: 'hard', nodes: r.nodes };
  return { bracket: 'master', nodes: r.nodes };
}
