import type { Game } from '../engine/index.js';
import type { DifficultyBracket } from '../solver/index.js';

const KEY = (iso: string) => `bilko_cellar_daily_${iso}`;

export function readDailyCache(iso: string): { game: Game; bracket: DifficultyBracket } | null {
  try {
    const raw = localStorage.getItem(KEY(iso));
    if (!raw) return null;
    return JSON.parse(raw) as { game: Game; bracket: DifficultyBracket };
  } catch {
    return null;
  }
}

export function writeDailyCache(iso: string, game: Game, bracket: DifficultyBracket): void {
  try {
    localStorage.setItem(KEY(iso), JSON.stringify({ game, bracket }));
  } catch {}
}

/** Evict daily caches older than 30 days. */
export function evictOldDailyCaches(): void {
  try {
    const cutoff = new Date(Date.now() - 30 * 86_400_000);
    const cutoffIso = cutoff.toISOString().slice(0, 10);
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k?.startsWith('bilko_cellar_daily_')) {
        const iso = k.replace('bilko_cellar_daily_', '');
        if (iso < cutoffIso) localStorage.removeItem(k);
      }
    }
  } catch {}
}
