import { useGameStore } from '../../state/store.js';
import { IconPause, IconPlay } from './icons.js';

export function PauseButton({ paused }: { paused: boolean }) {
  const onClick = () => {
    const s = useGameStore.getState();
    if (s.status === 'paused') {
      // Resume: shift startedAt forward by the pause duration so elapsed accumulates correctly.
      const pauseDuration = s.pausedAt !== null ? Date.now() - s.pausedAt : 0;
      useGameStore.setState({
        status: 'playing',
        startedAt: s.startedAt !== null ? s.startedAt + pauseDuration : Date.now(),
        pausedAt: null,
      });
    } else if (s.status === 'playing') {
      useGameStore.setState({ status: 'paused', pausedAt: Date.now() });
    }
  };

  return (
    <button className="ce-hud-btn" onClick={onClick} aria-label={paused ? 'Resume' : 'Pause'}>
      {paused ? <IconPlay /> : <IconPause />}
      <span className="ce-hud-btn-label">{paused ? 'Resume' : 'Pause'}</span>
    </button>
  );
}
