import { useState } from 'react';
import { bus } from '../../lib/bus.js';
import { IconUndo } from './icons.js';

export function UndoButton({ disabled }: { disabled: boolean }) {
  const [acking, setAcking] = useState(false);

  const onClick = () => {
    setAcking(true);
    bus.emit('undoRequested', {});
  };

  return (
    <button
      className={`ce-hud-btn${acking ? ' ce-hud-btn-ack' : ''}`}
      disabled={disabled}
      onClick={onClick}
      onAnimationEnd={() => setAcking(false)}
      aria-label="Undo last move"
    >
      <IconUndo />
      <span className="ce-hud-btn-label">Undo</span>
    </button>
  );
}
