import { useState } from 'react';
import { bus } from '../../lib/bus.js';
import { Popover } from './Popover.js';
import { IconRestart } from './icons.js';
import { useGameStore } from '../../state/store.js';

export function RestartButton({ moves }: { moves: number }) {
  const [confirmOpen, setConfirmOpen] = useState(false);
  const game = useGameStore((s) => s.game);

  const onClick = () => {
    if (moves <= 5) {
      bus.emit('restartRequested', {});
    } else {
      setConfirmOpen(true);
    }
  };

  return (
    <>
      <button className="ce-hud-btn" onClick={onClick} aria-label="Restart deal">
        <IconRestart />
        <span className="ce-hud-btn-label">Restart</span>
      </button>
      {confirmOpen && (
        <Popover anchor="restart" onClose={() => setConfirmOpen(false)}>
          <p>Restart deal #{String(game.dealNumber).padStart(5, '0')}? Your time and moves will reset.</p>
          <div className="ce-popover-actions">
            <button onClick={() => setConfirmOpen(false)}>Cancel</button>
            <button
              className="ce-popover-primary"
              onClick={() => {
                bus.emit('restartRequested', {});
                setConfirmOpen(false);
              }}
            >
              Restart
            </button>
          </div>
        </Popover>
      )}
    </>
  );
}
