import { useState } from 'react';
import type { CellarHistory } from '../../state/store.js';
import { bus } from '../../lib/bus.js';
import { isoDateLocal } from '../../state/utils.js';

function monthGrid(month: Date): Date[] {
  const firstDay = new Date(month.getFullYear(), month.getMonth(), 1);
  const lastDay = new Date(month.getFullYear(), month.getMonth() + 1, 0);
  const days: Date[] = [];
  // Pad with previous month days (Mon = first day of week).
  const firstDow = (firstDay.getDay() + 6) % 7; // 0=Mon
  for (let i = firstDow; i > 0; i--) {
    days.push(new Date(firstDay.getTime() - i * 86_400_000));
  }
  for (let d = 1; d <= lastDay.getDate(); d++) {
    days.push(new Date(month.getFullYear(), month.getMonth(), d));
  }
  return days;
}

function formatMonthYear(d: Date): string {
  return d.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
}

function prevMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth() - 1, 1);
}

function nextMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth() + 1, 1);
}

interface CalendarDialogProps {
  onClose: () => void;
  history: CellarHistory;
}

export function CalendarDialog({ onClose, history }: CalendarDialogProps) {
  const [month, setMonth] = useState(() => new Date());
  const days = monthGrid(month);
  const today = isoDateLocal(new Date());

  return (
    <div className="ce-cal-backdrop" onClick={onClose}>
      <div className="ce-cal" onClick={(e) => e.stopPropagation()}>
        <header>
          <button onClick={() => setMonth(prevMonth(month))} aria-label="Previous month">‹</button>
          <span>{formatMonthYear(month)}</span>
          <button onClick={() => setMonth(nextMonth(month))} aria-label="Next month">›</button>
        </header>
        <div className="ce-cal-grid">
          {days.map((d) => {
            const iso = isoDateLocal(d);
            const inMonth = d.getMonth() === month.getMonth();
            const future = iso > today;
            const won = history.daily.completedDays.includes(iso);
            const isToday = iso === today;

            return (
              <button
                key={iso}
                disabled={future || !inMonth}
                className={`ce-cal-cell${isToday ? ' is-today' : ''}${won ? ' is-won' : ''}`}
                onClick={() => {
                  bus.emit('newDealRequested', { daily: true, dailyDate: iso });
                  onClose();
                }}
              >
                <span className="ce-cal-day">{d.getDate()}</span>
                <span className="ce-cal-mark">{future ? '🔒' : won ? '✓' : '·'}</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}
