import { useState, useEffect, useRef } from 'react';
import { ThemeSwitcher } from '../features/themes/ThemeSwitcher.js';
import { LiveRegion } from '../features/themes/a11y/LiveRegion.js';
import '../styles/theme.css';

export function ThemeSlot() {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    function handleClickOutside(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [open]);

  return (
    <>
      <LiveRegion />
      <div className="ce-themer" ref={ref}>
        <button
          className="ce-themer-trigger"
          onClick={() => setOpen((o) => !o)}
          aria-label="Choose theme"
          aria-expanded={open}
          aria-haspopup="true"
        >
          🎨
        </button>
        {open && (
          <div className="ce-themer-popover">
            <ThemeSwitcher />
          </div>
        )}
      </div>
    </>
  );
}
