import type { Game } from '../engine/index.js';

/** Lower is better. Optimized for "make foundation progress". */
export function heuristic(g: Game): number {
  // 1. Cards off the foundations (weighted by 4).
  const foundationSum = g.foundations.reduce<number>((a, r) => a + r, 0);
  const cardsOff = 52 - foundationSum;

  // 2. Buried aces penalty.
  let buriedAces = 0;
  for (const cc of g.cascades) {
    for (let i = 0; i < cc.length - 1; i++) {
      if (cc[i]!.rank === 1) buriedAces += cc.length - 1 - i;
    }
  }

  // 3. Out-of-place adjacency violations.
  let outOfPlaceColor = 0;
  for (const cc of g.cascades) {
    for (let i = 1; i < cc.length; i++) {
      const a = cc[i - 1]!, b = cc[i]!;
      const colA = a.suit === 'D' || a.suit === 'H' ? 'r' : 'b';
      const colB = b.suit === 'D' || b.suit === 'H' ? 'r' : 'b';
      if (b.rank !== a.rank - 1 || colA === colB) outOfPlaceColor += 1;
    }
  }

  return 4 * cardsOff + 8 * buriedAces + outOfPlaceColor;
}
