import type { Game } from '../engine/index.js';
import { dealFromDate } from '../engine/index.js';
import { solve, type SolveOpts, type SolveResult } from './solve.js';

export interface DailySolveResult {
  game: Game;
  result: SolveResult;
}

/**
 * For a given ISO date string, hash to a candidate deal and verify solvability.
 * Retries up to 8 times with perturbed keys if the first deal is unsolvable.
 */
export function solveDaily(isoDate: string, opts: SolveOpts = {}): DailySolveResult {
  for (let i = 0; i < 8; i++) {
    const key = i === 0 ? isoDate : `${isoDate}#${i}`;
    const game = dealFromDate(key);
    const result = solve(game, opts);
    if (result.solvable) return { game, result };
  }
  // All perturbations exhausted — return last attempt.
  const game = dealFromDate(isoDate);
  return { game, result: solve(game, opts) };
}
