import { create } from 'zustand';
import {
  deal,
  applyMove,
  undo,
  isWon,
  safeAutoMove,
  canAutoFlush as engineCanAutoFlush,
  autoFlushSteps,
  type Game,
  type Position,
  type Step,
  type Move,
} from '../engine/index.js';
import { solveDaily, classifyDifficulty, type DifficultyBracket } from '../solver/index.js';
import { bus } from '../lib/bus.js';
import { isoDateLocal } from './utils.js';
import { readDailyCache, writeDailyCache } from './daily-cache.js';
import { recordWin, clearInProgressSave } from './history.js';

export type Status = 'idle' | 'playing' | 'won' | 'conceded' | 'paused';

export interface CellarState {
  game: Game;
  status: Status;
  daily: boolean;
  bracket: DifficultyBracket;
  startedAt: number | null;
  pausedAt: number | null;
  endedAt: number | null;
  moves: number;
  hintsUsed: number;
  canAutoFlush: boolean;
  schemaVersion: 1;
}

export interface CellarHistory {
  schemaVersion: 1;
  bestTimeMs: Partial<Record<DifficultyBracket, number>>;
  bestMoves: Partial<Record<DifficultyBracket, number>>;
  totalWins: number;
  totalDeals: number;
  playedDeals: Record<
    number,
    { wins: number; bestTimeMs: number; bestMoves: number; lastPlayed: string }
  >;
  daily: {
    streak: number;
    longestStreak: number;
    lastWonIsoDate: string | null;
    streakFreezes: { availableThisWeek: 0 | 1; weekOf: string };
    completedDays: string[];
  };
}

export const SAVE_KEY = 'bilko_cellar_save_v1';

function reverseStep(s: Step): Step {
  return { from: s.to, to: s.from, card: s.card };
}

const defaultGame = deal(1);

type StoreActions = {
  newDeal: (opts: { dealNumber?: number; daily?: boolean; dailyDate?: string }) => void;
  doMove: (from: Position, to: Position) => void;
  doUndo: () => void;
  doRestart: () => void;
  doConcede: () => void;
  noteHintUsed: () => void;
  hydrate: (snapshot: Partial<CellarState>) => void;
  triggerAutoFlush: () => void;
};

export const useGameStore = create<CellarState & StoreActions>((set, get) => ({
  game: defaultGame,
  status: 'idle' as Status,
  daily: false,
  bracket: 'standard' as DifficultyBracket,
  startedAt: null,
  pausedAt: null,
  endedAt: null,
  moves: 0,
  hintsUsed: 0,
  canAutoFlush: false,
  schemaVersion: 1,

  newDeal({ dealNumber, daily, dailyDate }) {
    let game: Game;
    const isDaily = !!daily;
    let bracket: DifficultyBracket;

    if (isDaily) {
      const dateKey = dailyDate ?? isoDateLocal(new Date());
      const cached = readDailyCache(dateKey);
      if (cached) {
        game = cached.game;
        bracket = cached.bracket;
      } else {
        const res = solveDaily(dateKey);
        game = res.game;
        const cls = classifyDifficulty(game.dealNumber, { nodeCap: 50_000, timeoutMs: 1_500 });
        bracket = cls.bracket;
        writeDailyCache(dateKey, game, bracket);
      }
    } else {
      const dn = dealNumber ?? Math.floor(Math.random() * 1_000_000) + 1;
      game = deal(dn);
      bracket = classifyDifficulty(dn, { nodeCap: 5_000, timeoutMs: 200 }).bracket;
    }

    set({
      game,
      status: 'playing',
      daily: isDaily,
      bracket,
      startedAt: Date.now(),
      pausedAt: null,
      endedAt: null,
      moves: 0,
      hintsUsed: 0,
      canAutoFlush: false,
    });
  },

  doMove(from, to) {
    const s = get();
    if (s.status !== 'playing') return;

    const r = applyMove(s.game, from, to);
    if (!r.ok) {
      bus.emit('moveRejected', { from, to, reason: r.reason ?? 'unknown' });
      return;
    }

    let game = r.game;
    const stepCount = r.move!.steps.length;
    bus.emit('moveApplied', { steps: r.move!.steps, supermove: r.move!.supermove });

    // Safe auto-flush after player move.
    const autoSteps = safeAutoMove(game);
    for (const st of autoSteps) {
      const ar = applyMove(game, st.from, st.to);
      if (ar.ok) game = ar.game;
    }
    if (autoSteps.length) bus.emit('moveApplied', { steps: autoSteps, supermove: false });

    const newMoves = s.moves + stepCount + autoSteps.length;

    if (isWon(game)) {
      const endedAt = Date.now();
      const timeMs = endedAt - (s.startedAt ?? endedAt);
      set({ game, moves: newMoves, status: 'won', endedAt, canAutoFlush: false });
      bus.emit('gameWon', { dealNumber: game.dealNumber, daily: s.daily, timeMs, moves: newMoves });
      recordWin({ dealNumber: game.dealNumber, daily: s.daily, bracket: s.bracket, timeMs, moves: newMoves });
      clearInProgressSave();
      return;
    }

    set({
      game,
      moves: newMoves,
      canAutoFlush: engineCanAutoFlush(game),
    });
  },

  doUndo() {
    const s = get();
    if (s.status !== 'playing') return;
    const r = undo(s.game);
    if (!r.ok) return;
    const stepsReversed = r.move!.steps.slice().reverse().map(reverseStep);
    bus.emit('moveApplied', { steps: stepsReversed, supermove: r.move!.supermove });
    set({ game: r.game, moves: s.moves + 1, canAutoFlush: false });
  },

  doRestart() {
    const s = get();
    set({
      game: deal(s.game.dealNumber, s.game.settings),
      status: 'playing',
      startedAt: Date.now(),
      pausedAt: null,
      endedAt: null,
      moves: 0,
      hintsUsed: 0,
      canAutoFlush: false,
    });
  },

  doConcede() {
    set({ status: 'conceded', endedAt: Date.now() });
    clearInProgressSave();
  },

  noteHintUsed() {
    set((s) => ({ hintsUsed: s.hintsUsed + 1 }));
  },

  hydrate(snap) {
    set(snap);
  },

  triggerAutoFlush() {
    const s = get();
    if (!s.canAutoFlush) return;
    const steps: Step[] = autoFlushSteps(s.game);
    if (!steps.length) return;
    let cur = s.game;
    for (const st of steps) {
      const ar = applyMove(cur, st.from, st.to);
      if (ar.ok) cur = ar.game;
    }
    const endedAt = Date.now();
    const timeMs = endedAt - (s.startedAt ?? endedAt);
    const newMoves = s.moves + steps.length;
    set({ game: cur, moves: newMoves, status: 'won', endedAt, canAutoFlush: false });
    bus.emit('moveApplied', { steps, supermove: false });
    bus.emit('gameWon', { dealNumber: cur.dealNumber, daily: s.daily, timeMs, moves: newMoves });
    recordWin({ dealNumber: cur.dealNumber, daily: s.daily, bracket: s.bracket, timeMs, moves: newMoves });
    clearInProgressSave();
  },
}));

// Bus → store wiring.
bus.on('moveRequested', ({ from, to }) => useGameStore.getState().doMove(from, to));
bus.on('undoRequested', () => useGameStore.getState().doUndo());
bus.on('restartRequested', () => useGameStore.getState().doRestart());
bus.on('newDealRequested', ({ dealNumber, daily, dailyDate }) =>
  useGameStore.getState().newDeal({ dealNumber, daily, dailyDate })
);

export const useGameState = () => useGameStore();
export const useGameActions = () => {
  const { newDeal, doMove, doUndo, doRestart, doConcede, noteHintUsed, triggerAutoFlush } =
    useGameStore.getState();
  return { newDeal, doMove, doUndo, doRestart, doConcede, noteHintUsed, triggerAutoFlush };
};
