import type { Card, Color, Game, Rank, Suit } from './types.js';

export function color(c: Card): Color {
  return c.suit === 'D' || c.suit === 'H' ? 'red' : 'black';
}

export function suitToFoundationIdx(suit: Suit): 0 | 1 | 2 | 3 {
  switch (suit) {
    case 'C': return 0;
    case 'D': return 1;
    case 'H': return 2;
    case 'S': return 3;
  }
}

export function topOfCascade(g: Game, idx: number): Card | null {
  const c = g.cascades[idx];
  if (!c || c.length === 0) return null;
  return c[c.length - 1]!;
}

export function cardAtPosition(g: Game, pos: { kind: string; index: number; row?: number }): Card | null {
  if (pos.kind === 'cascade') {
    const c = g.cascades[pos.index];
    if (!c) return null;
    const row = pos.row ?? c.length - 1;
    return c[row] ?? null;
  }
  if (pos.kind === 'cell') {
    return g.cells[pos.index] ?? null;
  }
  if (pos.kind === 'foundation') {
    const rank = g.foundations[pos.index];
    if (!rank) return null;
    // Return the top card of the foundation
    const suits: Suit[] = ['C', 'D', 'H', 'S'];
    return { rank: rank as Rank, suit: suits[pos.index]! };
  }
  return null;
}

export function emptyCellCount(g: Game): number {
  return g.cells.filter((c) => c === null).length;
}

export function emptyCascadeCount(g: Game): number {
  return g.cascades.filter((cc) => cc.length === 0).length;
}

export function maxSupermoveSize(g: Game, destIsEmptyCascade: boolean): number {
  const cells = emptyCellCount(g);
  const cascades = emptyCascadeCount(g) - (destIsEmptyCascade ? 1 : 0);
  return (1 + cells) * Math.pow(2, Math.max(0, cascades));
}

export function oppositeColorFoundations(suit: Suit, foundations: ReadonlyArray<0 | Rank>): [number, number] {
  // Clubs(0) and Spades(3) are black; Diamonds(1) and Hearts(2) are red.
  if (suit === 'C' || suit === 'S') {
    // Black suit — opposite is red (diamonds=1, hearts=2)
    return [foundations[1]!, foundations[2]!];
  } else {
    // Red suit — opposite is black (clubs=0, spades=3)
    return [foundations[0]!, foundations[3]!];
  }
}

export function cardName(c: Card): string {
  const rankNames: Record<number, string> = {
    1: 'Ace', 2: 'Two', 3: 'Three', 4: 'Four', 5: 'Five',
    6: 'Six', 7: 'Seven', 8: 'Eight', 9: 'Nine', 10: 'Ten',
    11: 'Jack', 12: 'Queen', 13: 'King',
  };
  const suitNames: Record<Suit, string> = {
    C: 'Clubs', D: 'Diamonds', H: 'Hearts', S: 'Spades',
  };
  return `${rankNames[c.rank]!} of ${suitNames[c.suit]}`;
}

export function cardShort(c: Card): string {
  const r = c.rank === 1 ? 'A' : c.rank === 11 ? 'J' : c.rank === 12 ? 'Q' : c.rank === 13 ? 'K' : String(c.rank);
  return `${r}${c.suit}`;
}
