import { useEffect, useRef, useState } from 'react';
import type { Game, Position, Card as CardType } from '../../engine/index.js';
import { cardName, suitToFoundationIdx, legalMoves } from '../../engine/index.js';
import { bus } from '../../lib/bus.js';
import { Cascade } from './Cascade.js';
import { Cell } from './Cell.js';
import { Foundation } from './Foundation.js';
import { useStepListPlayer } from './animation.js';
import { useSelection } from './selection.js';
import './board.css';

function positionsEqual(a: Position, b: Position): boolean {
  if (a.kind !== b.kind || a.index !== b.index) return false;
  if (a.kind === 'cascade' && b.kind === 'cascade') return a.row === b.row;
  return true;
}

function canBeSource(game: Game, pos: Position): boolean {
  if (pos.kind === 'cascade') {
    const c = game.cascades[pos.index];
    return !!c && c.length > 0;
  }
  if (pos.kind === 'cell') return game.cells[pos.index] !== null;
  if (pos.kind === 'foundation') return !game.settings.foundationLocked && game.foundations[pos.index] !== 0;
  return false;
}

function cardAtSelection(game: Game, sel: Position): CardType {
  if (sel.kind === 'cascade') {
    const c = game.cascades[sel.index]!;
    return c[sel.row]!;
  }
  if (sel.kind === 'cell') return game.cells[sel.index]!;
  // Foundation
  const suits = ['C', 'D', 'H', 'S'] as const;
  return { rank: game.foundations[sel.index]! as CardType['rank'], suit: suits[sel.index]! };
}

interface BoardProps {
  game: Game;
  interactive: boolean;
}

export function Board({ game, interactive }: BoardProps) {
  const { selection, select, clear, legalTargetsFor } = useSelection(game);
  const { animatingFromBus } = useStepListPlayer();
  const containerRef = useRef<HTMLDivElement>(null);
  const [, setBoardWidth] = useState(0);

  useEffect(() => {
    if (!containerRef.current) return;
    const ro = new ResizeObserver(([e]) => setBoardWidth(e!.contentRect.width));
    ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, []);

  const legalTargets = legalTargetsFor(selection);

  function commitOrSelect(target: Position) {
    if (!selection) {
      if (canBeSource(game, target)) select(target);
      return;
    }
    // We have a selection; this tap is the destination.
    bus.emit('moveRequested', {
      from: selection,
      to: target,
      card: cardAtSelection(game, selection),
    });
    clear();
  }

  function onCellTap(i: number) {
    commitOrSelect({ kind: 'cell', index: i as 0 | 1 | 2 | 3 });
  }

  function onFoundationTap(i: number) {
    commitOrSelect({ kind: 'foundation', index: i as 0 | 1 | 2 | 3 });
  }

  function onCascadeTap(cascIdx: number, row: number) {
    commitOrSelect({ kind: 'cascade', index: cascIdx as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row });
  }

  return (
    <div
      ref={containerRef}
      className="ms-board"
      data-animating={animatingFromBus || undefined}
      onClick={(e) => {
        // Click on board background → deselect.
        if ((e.target as HTMLElement).classList.contains('ms-board')) clear();
      }}
    >
      <div className="ms-top-row">
        <div className="ms-cells">
          {game.cells.map((c, i) => (
            <Cell
              key={i}
              index={i as 0 | 1 | 2 | 3}
              card={c}
              selected={selection?.kind === 'cell' && selection.index === i}
              legalTarget={legalTargets?.some((t) => t.kind === 'cell' && t.index === i)}
              onTap={() => onCellTap(i)}
            />
          ))}
        </div>
        <div className="ms-gap" aria-hidden />
        <div className="ms-foundations">
          {game.foundations.map((rank, i) => (
            <Foundation
              key={i}
              index={i as 0 | 1 | 2 | 3}
              top={rank}
              legalTarget={legalTargets?.some((t) => t.kind === 'foundation' && t.index === i)}
              onTap={() => onFoundationTap(i)}
            />
          ))}
        </div>
      </div>
      <div className="ms-cascades">
        {game.cascades.map((cascade, idx) => (
          <Cascade
            key={idx}
            index={idx as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7}
            cards={cascade}
            selection={
              selection?.kind === 'cascade' && selection.index === idx
                ? selection
                : null
            }
            legalTarget={legalTargets?.some((t) => t.kind === 'cascade' && t.index === idx)}
            onCardTap={(row) => onCascadeTap(idx, row)}
            interactive={interactive && !animatingFromBus}
          />
        ))}
      </div>
    </div>
  );
}
