import { useState } from 'react';
import { applyTheme, readTheme, type Theme } from './themeController.js';

const OPTIONS: Array<{ value: Theme; label: string }> = [
  { value: 'light', label: 'Light' },
  { value: 'dark', label: 'Dark' },
  { value: 'hc', label: 'HC' },
  { value: 'cb', label: 'CB' },
];

export function ThemeSwitcher() {
  const [theme, setTheme] = useState<Theme>(() => {
    try { return readTheme(); } catch { return 'light'; }
  });

  return (
    <div className="ce-settings-chips" role="radiogroup" aria-label="Choose theme">
      {OPTIONS.map((o) => (
        <button
          key={o.value}
          role="radio"
          aria-checked={theme === o.value}
          className={`ce-settings-chip${theme === o.value ? ' is-active' : ''}`}
          onClick={() => {
            setTheme(o.value);
            applyTheme(o.value);
          }}
        >
          {o.label}
        </button>
      ))}
    </div>
  );
}
