import type { Card, Game, Step } from './types.js';
import { color, maxSupermoveSize } from './helpers.js';
import { applyStep } from './apply.js';

/** How many cards starting at `row` form a valid alternating-color descending run to the end of the cascade. */
export function runSizeAt(g: Game, casc: number, row: number): number {
  const c = g.cascades[casc]!;
  if (row >= c.length) return 0;
  let n = 1;
  for (let i = row; i < c.length - 1; i++) {
    const a = c[i]!, b = c[i + 1]!;
    if (b.rank !== a.rank - 1) break;
    if (color(a) === color(b)) break;
    n += 1;
  }
  return n;
}

/**
 * Resolve a supermove of `runLen = casc[srcIdx].length - srcRow` cards
 * from cascade srcIdx to cascade dstIdx. Returns Step[] (each a single-card
 * atomic move) or null if the move exceeds the cap.
 *
 * Correctness invariant: every step moves the CURRENT accessible top card
 * of its source cascade (or a free cell). We maintain a virtual game state
 * so row indices are always correct for undo as well.
 *
 * Time: O(N) where N = runLen.
 */
export function resolveSupermove(
  g: Game,
  srcIdx: number,
  srcRow: number,
  dstIdx: number
): Step[] | null {
  const casc = g.cascades[srcIdx]!;
  const runLen = casc.length - srcRow;
  if (runLen <= 0) return null;

  const destIsEmpty = g.cascades[dstIdx]!.length === 0;
  if (runLen > maxSupermoveSize(g, destIsEmpty)) return null;

  const freeCellSlots: number[] = [];
  for (let i = 0; i < 4; i++) if (g.cells[i] === null) freeCellSlots.push(i);

  const emptyCascadeSlots: number[] = [];
  for (let i = 0; i < 8; i++) {
    if (i !== dstIdx && g.cascades[i]!.length === 0) emptyCascadeSlots.push(i);
  }

  const steps: Step[] = [];
  let vg = g; // virtual state updated as steps are generated

  /**
   * Move the top `n` cards of cascade `src` onto cascade `dst`.
   * `availCells` and `availCascs` are scratch resources for this sub-problem.
   *
   * Algorithm (recursive halving):
   *   n == 1  → base case: emit one step
   *   n > 1, casc available → stage top (n-1) in temp casc, move 1 to dst, unstage
   *   n > 1, cells only   → park top card in cell, move (n-1), unpark
   */
  function moveTopN(
    src: number,
    dst: number,
    n: number,
    availCells: number[],
    availCascs: number[]
  ): void {
    if (n === 0) return;

    if (n === 1) {
      const srcCasc = vg.cascades[src]!;
      const card = srcCasc[srcCasc.length - 1]!;
      const dstRow = vg.cascades[dst]!.length; // index where card will land (for undo)
      const step: Step = {
        from: { kind: 'cascade', index: src as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row: srcCasc.length - 1 },
        to:   { kind: 'cascade', index: dst as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row: dstRow },
        card,
      };
      steps.push(step);
      vg = applyStep(vg, step);
      return;
    }

    if (availCascs.length > 0) {
      // Stage top (n-1) in temp cascade, move head to dst, unstage.
      const temp = availCascs[0]!;
      const restCascs = availCascs.slice(1);
      moveTopN(src, temp, n - 1, availCells, restCascs);
      moveTopN(src, dst,  1,     availCells, restCascs);
      moveTopN(temp, dst, n - 1, availCells, restCascs);
    } else {
      // Park top card in a free cell, move rest, then unpark.
      if (availCells.length === 0) throw new Error('Supermove: no scratch space');
      const cellIdx = availCells[0]!;
      const restCells = availCells.slice(1);

      const srcCasc = vg.cascades[src]!;
      const card = srcCasc[srcCasc.length - 1]!;

      const parkStep: Step = {
        from: { kind: 'cascade', index: src as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row: srcCasc.length - 1 },
        to:   { kind: 'cell',    index: cellIdx as 0 | 1 | 2 | 3 },
        card,
      };
      steps.push(parkStep);
      vg = applyStep(vg, parkStep);

      moveTopN(src, dst, n - 1, restCells, availCascs);

      const dstRow = vg.cascades[dst]!.length;
      const unparkStep: Step = {
        from: { kind: 'cell',    index: cellIdx as 0 | 1 | 2 | 3 },
        to:   { kind: 'cascade', index: dst as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row: dstRow },
        card,
      };
      steps.push(unparkStep);
      vg = applyStep(vg, unparkStep);
    }
  }

  try {
    moveTopN(srcIdx, dstIdx, runLen, freeCellSlots, emptyCascadeSlots);
  } catch {
    return null;
  }

  return steps;
}
