import { bus } from '../../lib/bus.js';
import { playSound } from './sounds.js';
import { haptic } from './haptics.js';

let booted = false;

export function attachFeedback(): void {
  if (booted) return;
  booted = true;

  bus.on('moveApplied', ({ steps, supermove }) => {
    if (supermove) {
      for (let i = 0; i < steps.length; i++) {
        setTimeout(() => {
          playSound('place', 0.5);
          haptic('place');
        }, i * 40);
      }
      return;
    }
    const single = steps[0];
    if (!single) return;
    if (single.to.kind === 'foundation') {
      const isKing = single.card.rank === 13;
      playSound(isKing ? 'win-foundation' : 'place', isKing ? 0.7 : 0.5);
      if (isKing) haptic('win');
      else haptic('place');
    } else {
      playSound('place', 0.4);
      haptic('place');
    }
  });

  bus.on('moveRejected', () => {
    playSound('illegal');
    haptic('illegal');
  });

  bus.on('gameWon', () => {
    playSound('win', 0.8);
    haptic('win');
  });
}
