import { useState } from 'react';
import { buildShareTile } from './shareTile.js';
import type { DifficultyBracket } from '../../solver/index.js';

interface ShareButtonProps {
  isoDate: string;
  bracket: DifficultyBracket;
  dealNumber: number;
  timeMs: number;
  moves: number;
  solverMoves: number | null;
  streakAlive: boolean;
}

export function ShareButton(opts: ShareButtonProps) {
  const [copied, setCopied] = useState(false);

  const onClick = async () => {
    const text = buildShareTile(opts);
    if (navigator.share) {
      try {
        await navigator.share({ text });
        return;
      } catch {}
    }
    await navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2_000);
  };

  return (
    <button className="ce-share" onClick={onClick}>
      {copied ? 'Copied ✓' : 'Share'}
    </button>
  );
}
