export type Theme = 'light' | 'dark' | 'hc' | 'cb';

const KEY = 'bilko_cellar_theme';

export function readTheme(): Theme {
  try {
    const stored = localStorage.getItem(KEY) as Theme | null;
    if (stored && ['light', 'dark', 'hc', 'cb'].includes(stored)) return stored;
    if (window.matchMedia('(prefers-color-scheme: dark)').matches) return 'dark';
  } catch {}
  return 'light';
}

export function applyTheme(theme: Theme): void {
  document.documentElement.dataset.theme = theme;
  try {
    localStorage.setItem(KEY, theme);
  } catch {}
}

/** Call once before React mounts to avoid FOUC. */
export function hydrateThemeOnBoot(): void {
  applyTheme(readTheme());
}
