import type { Card, Game, Position, Rank } from './types.js';
import { color, suitToFoundationIdx, topOfCascade, maxSupermoveSize } from './helpers.js';
import { runSizeAt } from './supermove.js';

/** Get the card at a position (for move validation). */
function cardAt(g: Game, pos: Position): Card | null {
  if (pos.kind === 'cascade') {
    const c = g.cascades[pos.index];
    if (!c || c.length === 0) return null;
    const row = pos.row ?? c.length - 1;
    return c[row] ?? null;
  }
  if (pos.kind === 'cell') {
    return g.cells[pos.index] ?? null;
  }
  if (pos.kind === 'foundation') {
    const rank = g.foundations[pos.index];
    if (!rank) return null;
    const suits = ['C', 'D', 'H', 'S'] as const;
    return { rank: rank as Rank, suit: suits[pos.index]! };
  }
  return null;
}

/**
 * Check if a move from `from` to `to` is legal.
 * For cascade→cascade runs, also checks supermove cap.
 */
export function isLegalMove(g: Game, from: Position, to: Position): boolean {
  const card = cardAt(g, from);
  if (!card) return false;

  if (to.kind === 'foundation') {
    const foundIdx = to.index;
    const foundTop = g.foundations[foundIdx]!;
    const expectedSuit = (['C', 'D', 'H', 'S'] as const)[foundIdx]!;
    if (card.suit !== expectedSuit) return false;
    if (foundTop !== card.rank - 1) return false;
    return true;
  }

  if (to.kind === 'cell') {
    // Only single cards to empty cells.
    if (g.cells[to.index] !== null) return false;
    // Only can move from top of cascade or from cell.
    if (from.kind === 'cascade') {
      const c = g.cascades[from.index]!;
      const row = from.row ?? c.length - 1;
      if (row !== c.length - 1) return false; // must be bottom card
    }
    // Foundation → cell not standard (but not explicitly blocked either).
    return true;
  }

  if (to.kind === 'cascade') {
    const dstCasc = g.cascades[to.index]!;

    // Foundation → cascade (allowed unless foundationLocked).
    if (from.kind === 'foundation') {
      if (g.settings.foundationLocked) return false;
      if (dstCasc.length === 0) return true;
      const dstTop = dstCasc[dstCasc.length - 1]!;
      return dstTop.rank === card.rank + 1 && color(dstTop) !== color(card);
    }

    if (from.kind === 'cell') {
      // Single card from cell to cascade.
      if (dstCasc.length === 0) return true;
      const dstTop = dstCasc[dstCasc.length - 1]!;
      return dstTop.rank === card.rank + 1 && color(dstTop) !== color(card);
    }

    if (from.kind === 'cascade') {
      // Determine run length from srcRow to end.
      const srcCasc = g.cascades[from.index]!;
      const srcRow = from.row ?? srcCasc.length - 1;

      if (dstCasc.length === 0) {
        // Empty cascade: check supermove cap.
        const runLen = srcCasc.length - srcRow;
        if (runLen > 1) {
          const runLen2 = runSizeAt(g, from.index, srcRow);
          if (runLen2 < runLen) return false; // not a valid run
          if (runLen > maxSupermoveSize(g, true)) return false;
        }
        return true;
      }

      const dstTop = dstCasc[dstCasc.length - 1]!;
      const runLen = srcCasc.length - srcRow;

      if (runLen === 1) {
        return dstTop.rank === card.rank + 1 && color(dstTop) !== color(card);
      }

      // Multi-card run: validate the run is proper alternating-color descending,
      // the head fits on dstTop, and supermove cap is not exceeded.
      const headCard = srcCasc[srcRow]!;
      if (dstTop.rank !== headCard.rank + 1 || color(dstTop) === color(headCard)) return false;
      const actualRun = runSizeAt(g, from.index, srcRow);
      if (actualRun < runLen) return false;
      if (runLen > maxSupermoveSize(g, false)) return false;
      return true;
    }
  }

  return false;
}

/** Return all legal moves from current state. */
export function legalMoves(g: Game): Array<{ from: Position; to: Position }> {
  const result: Array<{ from: Position; to: Position }> = [];

  // Collect all source positions.
  const sources: Position[] = [];

  // Cascade sources: each possible run start.
  for (let i = 0; i < 8; i++) {
    const c = g.cascades[i]!;
    for (let row = 0; row < c.length; row++) {
      sources.push({ kind: 'cascade', index: i as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row });
    }
  }

  // Cell sources.
  for (let i = 0; i < 4; i++) {
    if (g.cells[i] !== null) {
      sources.push({ kind: 'cell', index: i as 0 | 1 | 2 | 3 });
    }
  }

  // Foundation sources (if not locked).
  if (!g.settings.foundationLocked) {
    for (let i = 0; i < 4; i++) {
      if (g.foundations[i] !== 0) {
        sources.push({ kind: 'foundation', index: i as 0 | 1 | 2 | 3 });
      }
    }
  }

  // All destinations.
  const destinations: Position[] = [];
  for (let i = 0; i < 8; i++) {
    destinations.push({ kind: 'cascade', index: i as 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7, row: 0 });
  }
  for (let i = 0; i < 4; i++) {
    if (g.cells[i] === null) {
      destinations.push({ kind: 'cell', index: i as 0 | 1 | 2 | 3 });
    }
  }
  for (let i = 0; i < 4; i++) {
    destinations.push({ kind: 'foundation', index: i as 0 | 1 | 2 | 3 });
  }

  for (const from of sources) {
    for (const to of destinations) {
      // Skip self-moves.
      if (from.kind === to.kind && from.index === to.index) continue;
      if (isLegalMove(g, from, to)) {
        result.push({ from, to });
      }
    }
  }

  return result;
}
