import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';
import { hydrateThemeOnBoot } from './features/themes/themeController.js';
import App from './App.js';

// Apply theme before React mounts to avoid FOUC.
hydrateThemeOnBoot();

// Deep-link parser.
const url = new URL(window.location.href);
const dailyParam = url.searchParams.get('daily');
const dealParam = url.searchParams.get('deal');

if (dailyParam && /^\d{4}-\d{2}-\d{2}$/.test(dailyParam)) {
  // Import bus lazily to avoid circular; wait for store to be ready.
  setTimeout(() => {
    import('./lib/bus.js').then(({ bus }) => {
      bus.emit('newDealRequested', { daily: true, dailyDate: dailyParam });
    });
  }, 0);
} else if (dealParam && /^\d+$/.test(dealParam)) {
  const n = parseInt(dealParam, 10);
  if (n >= 1 && n <= 1_000_000) {
    setTimeout(() => {
      import('./lib/bus.js').then(({ bus }) => {
        bus.emit('newDealRequested', { dealNumber: n });
      });
    }, 0);
  }
}

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <App />
  </StrictMode>
);

// Expose test handles in dev builds so Playwright can drive the store.
if (import.meta.env.DEV) {
  Promise.all([
    import('./state/store.js'),
    import('./engine/index.js'),
    import('./lib/bus.js'),
  ]).then(([{ useGameStore }, engine, { bus }]) => {
    (window as unknown as Record<string, unknown>).__cellarStore = useGameStore;
    (window as unknown as Record<string, unknown>).__cellarEngine = engine;
    (window as unknown as Record<string, unknown>).__cellarBus = bus;
  });
}
