import type { Game, Card } from '../engine/index.js';

function cardCode(c: Card): number {
  const suitOffset = c.suit === 'C' ? 0 : c.suit === 'D' ? 1 : c.suit === 'H' ? 2 : 3;
  return (c.rank - 1) * 4 + suitOffset;
}

/** Compact string hash of a Game state. Used as Map key in the solver. */
export function hashGame(g: Game): string {
  // Cascade signature: each cascade as a sorted card-sequence (sort cascades for symmetry).
  const cascSigs: string[] = g.cascades.map((stack) =>
    stack.map((c) => String.fromCharCode(33 + cardCode(c))).join('')
  );
  cascSigs.sort();

  // Free cells: sort for symmetry (interchangeable).
  const cells = [...g.cells]
    .map((c) => (c ? String.fromCharCode(33 + cardCode(c)) : '-'))
    .sort()
    .join('');

  const found = g.foundations.map((r) => String.fromCharCode(48 + r)).join('');

  return cascSigs.join('|') + '/' + cells + '/' + found;
}
