import type { CSSProperties } from 'react';
import type { Card as CardType, Position } from '../../engine/index.js';
import { cardName, suitToFoundationIdx } from '../../engine/index.js';
import { Card } from './Card.js';
import { bus } from '../../lib/bus.js';

interface CascadeProps {
  index: 0 | 1 | 2 | 3 | 4 | 5 | 6 | 7;
  cards: ReadonlyArray<CardType>;
  selection: { kind: 'cascade'; index: number; row: number } | null;
  legalTarget?: boolean;
  onCardTap: (row: number) => void;
  interactive: boolean;
}

export function Cascade({ index, cards, selection, legalTarget, onCardTap, interactive }: CascadeProps) {
  const fan = cards.length > 12 ? 'var(--cascade-fan-compact)' : 'var(--cascade-fan-rest)';
  const topCard = cards.length > 0 ? cards[cards.length - 1] : null;
  const cascadeLabel = topCard
    ? `Cascade ${index + 1}, ${cards.length} card${cards.length !== 1 ? 's' : ''}, top: ${cardName(topCard)}`
    : `Cascade ${index + 1}, empty`;

  return (
    <div
      className={`ms-cascade${legalTarget ? ' is-target' : ''}`}
      data-cascade={index}
      role="group"
      aria-label={cascadeLabel}
    >
      {cards.length === 0 ? (
        <div
          className="ms-cascade-empty"
          onClick={() => onCardTap(0)}
          role="button"
          tabIndex={0}
          aria-label={`Empty cascade ${index + 1}`}
          onKeyDown={(e) => e.key === 'Enter' && onCardTap(0)}
        />
      ) : (
        cards.map((card, row) => {
          const isSource = selection?.row === row;
          const isBottom = row === cards.length - 1;
          const negMargin = row === 0 ? '0' : `calc(${fan} * var(--card-height) * -1)`;

          return (
            <button
              key={row}
              className={`ms-cascade-card${isSource ? ' is-source' : ''}`}
              style={
                {
                  marginTop: negMargin,
                  '--row': row,
                } as React.CSSProperties
              }
              disabled={!interactive}
              onClick={() => onCardTap(row)}
              onDoubleClick={() => {
                if (!isBottom) return;
                const foundIdx = suitToFoundationIdx(card.suit);
                bus.emit('moveRequested', {
                  from: { kind: 'cascade', index, row },
                  to: { kind: 'foundation', index: foundIdx },
                  card,
                });
              }}
              aria-label={`${cardName(card)} at row ${row + 1} of cascade ${index + 1}`}
            >
              <Card card={card} lifted={isSource} selected={isSource} />
            </button>
          );
        })
      )}
    </div>
  );
}
