import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus.js';

// Full cascade: 8 columns × up to 7 rows × 35ms = ~640ms + 160ms keyframe = ~800ms
const DEAL_MS = 900;
const REDUCED = typeof window !== 'undefined'
  ? window.matchMedia('(prefers-reduced-motion: reduce)').matches
  : false;

export function DealAnimation() {
  const [dealing, setDealing] = useState(false);

  useEffect(() => {
    const off = bus.on('newDealRequested', () => {
      if (REDUCED) return;
      setDealing(true);
      const t = window.setTimeout(() => setDealing(false), DEAL_MS);
      return () => window.clearTimeout(t);
    });
    return off;
  }, []);

  useEffect(() => {
    if (dealing) {
      document.documentElement.dataset.dealing = '';
    } else {
      delete document.documentElement.dataset.dealing;
    }
  }, [dealing]);

  // Tap-to-skip: any click during deal collapses the animation early.
  useEffect(() => {
    if (!dealing) return;
    function skip() {
      setDealing(false);
    }
    document.addEventListener('pointerdown', skip, { once: true });
    return () => document.removeEventListener('pointerdown', skip);
  }, [dealing]);

  if (!dealing) return null;
  return <div className="ce-deal-overlay" aria-hidden data-testid="cellar-deal-overlay" />;
}
