import type { DifficultyBracket } from '../../solver/index.js';

interface ShareTileOpts {
  isoDate: string;
  bracket: DifficultyBracket;
  dealNumber: number;
  timeMs: number;
  moves: number;
  solverMoves: number | null;
  streakAlive: boolean;
}

function formatMmSs(ms: number): string {
  const s = Math.floor(ms / 1000);
  const m = Math.floor(s / 60);
  const sec = s % 60;
  return `${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
}

function squareFor(opts: { timeMs: number; moves: number; solverMoves: number | null; streakAlive: boolean }): string {
  const t = opts.timeMs < 5 * 60_000 ? '🟩' : opts.timeMs < 12 * 60_000 ? '🟨' : '🟥';
  const m = opts.solverMoves
    ? opts.moves <= 1.5 * opts.solverMoves
      ? '🟩'
      : opts.moves <= 2.5 * opts.solverMoves
        ? '🟨'
        : '🟥'
    : '⬜';
  const s = opts.streakAlive ? '🟩' : '⬜';
  return `${t}${m}${s}`;
}

export function buildShareTile(opts: ShareTileOpts): string {
  const time = formatMmSs(opts.timeMs);
  const sq = squareFor(opts);
  const bLabel = ({ easy: 'Easy', standard: 'Standard', hard: 'Hard', master: 'Master', unsolvable: 'Unsolvable' } as const)[opts.bracket];
  return [
    `Cellar ${opts.isoDate} · ${bLabel} · #${String(opts.dealNumber).padStart(5, '0')} · ${time} · ${opts.moves} mvs ${sq}`,
    `https://bilko.run/projects/cellar/?daily=${opts.isoDate}`,
  ].join('\n');
}
