import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus.js';

const REDUCED = typeof window !== 'undefined'
  ? window.matchMedia('(prefers-reduced-motion: reduce)').matches
  : false;

const STEP_MS = REDUCED ? 0 : 80;
const STAGGER_MS = REDUCED ? 0 : 40;

export function useStepListPlayer(): { animatingFromBus: boolean } {
  const [animating, setAnimating] = useState(false);

  useEffect(() => {
    const off = bus.on('moveApplied', ({ steps, supermove }) => {
      const showSteps = localStorage.getItem('bilko_cellar_show_supermove_steps') !== 'off';
      if (!supermove || REDUCED || !showSteps) return;
      setAnimating(true);
      const totalMs = STAGGER_MS * (steps.length - 1) + STEP_MS;
      window.setTimeout(() => setAnimating(false), Math.max(totalMs, 50));
    });
    return off;
  }, []);

  return { animatingFromBus: animating };
}
