import { useEffect, useRef, type ReactNode } from 'react';

interface PopoverProps {
  anchor: string;
  onClose: () => void;
  children: ReactNode;
}

export function Popover({ anchor, onClose, children }: PopoverProps) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    ref.current?.focus();
  }, []);

  return (
    <>
      <div className="ce-popover-backdrop" onClick={onClose} />
      <div
        ref={ref}
        className="ce-popover"
        role="dialog"
        aria-modal="true"
        aria-label={anchor}
        tabIndex={-1}
        onKeyDown={(e) => e.key === 'Escape' && onClose()}
      >
        {children}
      </div>
    </>
  );
}
