import { useEffect, useState } from 'react';
import { bus } from '../../../lib/bus.js';
import { cardName } from '../../../engine/index.js';
import type { Position } from '../../../lib/bus.js';

function describePos(p: Position): string {
  if (p.kind === 'cascade') return `cascade ${p.index + 1}`;
  if (p.kind === 'cell') return `free cell ${p.index + 1}`;
  return `${(['clubs', 'diamonds', 'hearts', 'spades'] as const)[p.index]} foundation`;
}

function formatHumanTime(ms: number): string {
  const s = Math.floor(ms / 1000);
  const m = Math.floor(s / 60);
  const sec = s % 60;
  if (m === 0) return `${sec} seconds`;
  return `${m} minute${m === 1 ? '' : 's'} ${sec} seconds`;
}

export function LiveRegion() {
  const [msg, setMsg] = useState('');

  useEffect(() => {
    const offMove = bus.on('moveApplied', ({ steps, supermove }) => {
      if (supermove && steps.length > 1) {
        const head = steps[0]!;
        const last = steps[steps.length - 1]!;
        setMsg(`Run of ${steps.length} from ${describePos(head.from)} onto ${describePos(last.to)}.`);
      } else {
        const s = steps[0]!;
        setMsg(`${cardName(s.card)} moved from ${describePos(s.from)} to ${describePos(s.to)}.`);
      }
    });

    const offWin = bus.on('gameWon', ({ moves, timeMs }) => {
      setMsg(`Cellar complete. ${moves} moves, ${formatHumanTime(timeMs)}.`);
    });

    const offReject = bus.on('moveRejected', ({ reason }) => {
      setMsg(`Move not legal: ${reason}.`);
    });

    return () => {
      offMove();
      offWin();
      offReject();
    };
  }, []);

  return (
    <div role="status" aria-live="polite" aria-atomic="false" className="ce-sr-live">
      {msg}
    </div>
  );
}
