import { lazy, Suspense, useEffect, useState } from 'react';
import { bus } from '../../lib/bus.js';

const Tutorial = lazy(() =>
  import('./Tutorial.js').then((m) => ({ default: m.Tutorial })),
);

const STORAGE_KEY = 'cellar_seen_tutorial';

function hasSeenTutorial(): boolean {
  try {
    return window.localStorage.getItem(STORAGE_KEY) === '1';
  } catch {
    return true;
  }
}

// Only load the tutorial bundle when it's actually needed:
//   - first visit (no flag), OR
//   - reopen from Help button (tutorialRequested bus event).
//
// Once armed, we ALSO keep the Tutorial mounted so its own
// `tutorialRequested` listener can re-trigger subsequent opens
// (Skip → reopen) without forcing another module load.
export function TutorialLazy() {
  const [armed, setArmed] = useState<boolean>(() => !hasSeenTutorial());

  useEffect(() => {
    if (armed) return;
    const off = bus.on('tutorialRequested', () => setArmed(true));
    return off;
  }, [armed]);

  if (!armed) return null;
  return (
    <Suspense fallback={null}>
      <Tutorial />
    </Suspense>
  );
}
