// Microsoft C rand() family — 32-bit signed, take high 15 bits.
// state_{n+1} = (state_n * 214013 + 2531011) mod 2^31
// rand_n      = state_{n+1} >> 16          (15-bit unsigned, range [0, 32767])

export class MsLcg {
  private state: number;

  constructor(seed: number) {
    // Microsoft uses a 32-bit signed seed.
    this.state = seed >>> 0;
  }

  next15(): number {
    // (state * 214013 + 2531011) — use Math.imul for correct 32-bit signed integer multiply.
    // Add 2531011 safely (stays in float64 safe range).
    this.state = (Math.imul(this.state, 214013) + 2531011) & 0x7fffffff;
    return (this.state >> 16) & 0x7fff; // [0, 32767]
  }
}
