type AnySnapshot = { schemaVersion: number; [k: string]: unknown };

const MIGRATIONS: Record<number, (s: AnySnapshot) => AnySnapshot> = {
  // 0: (s) => ({ ...s, schemaVersion: 1, state: { ...(s.state as any), hintsUsed: 0 } }),
};

export function migrate(s: AnySnapshot): AnySnapshot {
  let cur = s;
  while (cur.schemaVersion < 1) {
    const m = MIGRATIONS[cur.schemaVersion as number];
    if (!m) return { schemaVersion: 1, state: null } as AnySnapshot;
    cur = m(cur);
  }
  return cur;
}
