import { useGameStore, SAVE_KEY, type CellarState } from './store.js';
import { migrate } from './migrations.js';

export interface SavedSnapshot {
  schemaVersion: 1;
  state: CellarState;
}

export function serializeSave(state: CellarState): string {
  const safe = JSON.parse(JSON.stringify(state)) as CellarState;
  return JSON.stringify({ schemaVersion: 1, state: safe } satisfies SavedSnapshot);
}

export function deserializeSave(raw: string): CellarState | null {
  try {
    const parsed = JSON.parse(raw) as { schemaVersion: number; [k: string]: unknown };
    if (parsed.schemaVersion === 1) return (parsed as unknown as SavedSnapshot).state;
    if (typeof parsed.schemaVersion === 'number' && parsed.schemaVersion < 1) {
      const migrated = migrate(parsed);
      if (migrated.schemaVersion === 1 && (migrated as unknown as { state: unknown }).state !== null) {
        return (migrated as unknown as SavedSnapshot).state;
      }
    }
    return null;
  } catch {
    return null;
  }
}

let saveTimer: ReturnType<typeof setTimeout> | null = null;

export function attachAutosave(): () => void {
  return useGameStore.subscribe((state) => {
    if (state.status !== 'playing') return;
    if (saveTimer !== null) clearTimeout(saveTimer);
    saveTimer = setTimeout(() => {
      try {
        localStorage.setItem(SAVE_KEY, serializeSave(state));
      } catch {
        // Quota exceeded — silently drop.
      }
    }, 400);
  });
}

export function tryHydrateOnBoot(): void {
  try {
    const raw = localStorage.getItem(SAVE_KEY);
    if (!raw) return;
    const snap = deserializeSave(raw);
    if (!snap || snap.status !== 'playing') return;
    useGameStore.getState().hydrate(snap);
  } catch {
    // localStorage unavailable.
  }
}
